    ctx.save(); ctx.shadowColor = 'rgba(0,0,0,.5)'; ctx.shadowBlur = 10; ctx.textAlign = 'left'; ctx.fillStyle = 'rgba(255,255,255,.9)'; ctx.fillText(sub, sX + av + gpx, ry); ctx.restore(); ctx.textAlign = 'center';
