// Objeto interactivo de cada sala: al tocarlo se abre su minijuego/actividad.
// (Las funciones openPerky* están declaradas más abajo — hoisting las hace accesibles.)
const PLZ_ACTIVITY = {
  plaza:   { furn: 'djbooth', open: () => openPerkyDance(),    w: 13, top: 44, hint: 'Toca la cabina para bailar en PerkyDance' },
  estudio: { furn: 'djbooth', open: () => openPerkyPads(),     w: 13, top: 44, hint: 'Toca la mesa para tocar la batería en PerkyPads' },
  azotea:  { furn: 'hoop',    open: () => openPerkyHoops(),     w: 14, top: 52, hint: 'Toca la canasta para jugar a PerkyHoops' },
  arcade:  { furn: 'arcade',  open: () => openPerkyInvaders(),  w: 11, top: 40, hint: 'Toca una recreativa para jugar a PerkyInvaders' },
  playa:   { furn: 'sea',     open: () => openPerkyFish(),      w: 16, top: 22, bot: 14, hint: 'Toca el mar para pescar en PerkyFish' },
};

let plaza = null;          // runtime del render (solo mientras la vista está abierta)
let plazaChan = null;      // canal del contador (badge del menú)
let plazaCount = 0;
let plzR = null;           // sala activa computada { def, furn, blocked, seats, dance, portals }
const plzCustomRooms = {}; // cache de salas de usuario: id -> { def, furn }

// convierte un registro de plaza_rooms en una def de sala utilizable y la cachea
function plzRoomFromRecord(rec) {
  const d = rec.data || {};
  const owner = rec.profiles ? (rec.profiles.display_name || rec.profiles.username) : '';
  const furn = Array.isArray(d.furn) ? d.furn.slice() : [];
  if (!furn.some(f => f.t === 'portal')) furn.push({ t: 'portal', i: 5, j: 9, to: 'plaza', spawn: [5, 6], label: 'Salir', col: '#27a9ff' });
  const def = {
    name: rec.name || 'Sala', sub: d.sub || (owner ? 'de ' + owner : 'Sala de la comunidad'),
    floorA: d.floorA || '#161c33', floorB: d.floorB || '#121729', wall: d.wall || '#0d1122',
    neonA: d.neonA || '#27a9ff', neonB: d.neonB || '#6e2df5', sign: (d.sign || rec.name || 'ROOM').toString().toUpperCase().slice(0, 10),
    dance: d.dance || [], custom: true, ownerId: rec.owner_id, roomId: rec.id, furn,
  };
  plzCustomRooms[rec.id] = { def, furn };
  return def;
}

function plzComputeRoom(id) {
  const custom = plzCustomRooms[id];
  const def = custom ? custom.def : (PLZ_ROOMS[id] || PLZ_ROOMS.plaza);
  const furn = custom ? custom.furn : def.furn;
  return { id, def, furn, dance: def.dance || [], ...plzCollisions(furn) };
}
// construye colisiones/asientos/portales considerando la huella de cada mueble
function plzCollisions(furn) {
  const blocked = new Set(), seats = new Map(), portals = new Map();
  for (const f of furn) {
    if (f.t === 'portal') { portals.set(f.i + ',' + f.j, f); continue; }
    const solid = plzIsSolid(f.t), seat = plzIsSeat(f);
    if (!solid && !seat) continue;
    for (const [ti, tj] of plzFurnTiles(f)) {
      if (solid) blocked.add(ti + ',' + tj);
      if (seat) seats.set(ti + ',' + tj, f);
    }
  }
  return { blocked, seats, portals };
}
// recomputa colisiones/asientos/portales tras editar el mobiliario en caliente
function plzRecompute() {
  if (!plzR) return;
  Object.assign(plzR, plzCollisions(plzR.furn));
}

const plzKey = (i, j) => i + ',' + j;
const plzFree = (i, j) => i >= 0 && j >= 0 && i < PLZ.COLS && j < PLZ.ROWS && plzR && !plzR.blocked.has(plzKey(i, j));

// BFS: camino entre dos casillas (rejilla pequeña, sobra)
function plzPath(from, to) {
  if (from.i === to.i && from.j === to.j) return [];
  const prev = new Map(); prev.set(plzKey(from.i, from.j), null);
  const q = [[from.i, from.j]];
  while (q.length) {
    const [ci, cj] = q.shift();
    if (ci === to.i && cj === to.j) break;
    for (const [di, dj] of [[1, 0], [-1, 0], [0, 1], [0, -1]]) {
      const ni = ci + di, nj = cj + dj;
      if (!plzFree(ni, nj) || prev.has(plzKey(ni, nj))) continue;
      prev.set(plzKey(ni, nj), [ci, cj]); q.push([ni, nj]);
    }
  }
  if (!prev.has(plzKey(to.i, to.j))) return null;
  const path = []; let cur = [to.i, to.j];
  while (cur) { path.unshift({ i: cur[0], j: cur[1] }); cur = prev.get(plzKey(cur[0], cur[1])); }
  path.shift();
  return path;
}

function plzEntity(meta, id) {
  const e = {
    id, username: meta.username || 'bro', name: meta.name || meta.username || 'bro',
    accent: meta.accent || '#3e57fc', hat: meta.hat || 'none', x: meta.i ?? 5, y: meta.j ?? 5,
    path: [], bubble: null, phase: Math.random() * 6.28, img: null, imgOk: false,
  };
  if (meta.avatar_url) {
    const im = new Image(); im.crossOrigin = 'anonymous';
    im.onload = () => { e.imgOk = true; }; im.src = czUrl ? czUrl(meta.avatar_url) : meta.avatar_url;
    e.img = im;
  }
  return e;
}

// canal realtime: se abre al iniciar sesión (para el badge) y se reutiliza en la vista
// canal global de conteo (badge del menú): cuenta a todos los que están en la Plaza (cualquier sala)
function initPlazaWatch() {
  if (plazaChan) return;
  try {
    plazaChan = sb.channel('plaza-world', { config: { presence: { key: state.user.id } } });
    plazaChan.on('presence', { event: 'sync' }, () => {
      plazaCount = Object.keys(plazaChan.presenceState()).length;
      const b = $('cntPlaza'); if (b) b.textContent = plazaCount > 0 ? String(plazaCount) : '';
    }).subscribe();
  } catch (_) {}
}

// entra en una sala: cambia el canal de tiempo real, mobiliario y suelo
function plzJoinRoom(id, si, sj) {
  if (!plaza) return;
  // limpiar estado de edición al cambiar de sala
  plaza.editing = false;
  const edPanel = document.getElementById('plazaEditor'); if (edPanel) edPanel.remove();
  plzHideEditFab();
  const dk = document.querySelector('.plaza-dock'); if (dk) dk.style.display = '';
  const ht = document.querySelector('.plaza-hint'); if (ht) ht.style.display = '';
  // salir del canal de la sala anterior
  if (plaza.chan) { try { plaza.chan.untrack(); } catch (_) {} try { sb.removeChannel(plaza.chan); } catch (_) {} plaza.chan = null; }
  plzR = plzComputeRoom(id);
  plaza.roomId = id;
  const me = plaza.me;
  if (!plzFree(si, sj)) { si = 5; sj = 6; }
  me.x = si; me.y = sj; me.path = []; me.emote = null;
  plaza.ents = new Map([[state.user.id, me]]);
  plaza.target = null;
  plzPrerenderFloor();
  // cabecera
  const h = $('plazaRoomName'); if (h) h.textContent = plzR.def.name;
  const s = $('plazaRoomSub'); if (s) s.textContent = plzR.def.sub;
  const n = $('plazaLiveN'); if (n) n.textContent = '1';
  const act0 = PLZ_ACTIVITY[id];
  if (act0 && act0.hint) setTimeout(() => { if (plaza && plaza.roomId === id) toast(act0.hint); }, 550);

  // canal de la sala: presencia (roster) + movimiento + chat + emotes
  plaza.chan = sb.channel('plaza-room-' + id, { config: { presence: { key: state.user.id }, broadcast: { self: false } } });
  plaza.chan
    .on('presence', { event: 'sync' }, () => { if (plaza && plaza.roomId === id) plzSyncRoster(plaza.chan.presenceState()); })
    .on('broadcast', { event: 'move' }, ({ payload }) => {
      if (!plaza || !payload || payload.id === state.user.id || isHidden(payload.id)) return;
      const e = plaza.ents.get(payload.id); if (!e) return;
      if (payload.from) { e.x = payload.from.i; e.y = payload.from.j; }
      e.path = payload.path || [];
    })
    .on('broadcast', { event: 'chat' }, ({ payload }) => {
      if (!plaza || !payload || isHidden(payload.id)) return;
      const e = plaza.ents.get(payload.id);
      if (e) e.bubble = { text: String(payload.text || '').slice(0, 140), until: performance.now() + 6500 };
    })
    .on('broadcast', { event: 'emote' }, ({ payload }) => {
      if (!plaza || !payload || isHidden(payload.id)) return;
      const e = plaza.ents.get(payload.id);
      if (payload.kind === 'react') {
        const t = payload.target ? plaza.ents.get(payload.target) : e;
        if (t && payload.emoji) t.float = { emoji: payload.emoji, until: performance.now() + 2600 };
        return;
      }
      const dur = payload.kind === 'dance' ? 12000 : 2600;
      if (e) e.emote = { kind: payload.kind, until: performance.now() + dur, target: payload.target || null };
      if (payload.target === state.user.id) {
        const who = e ? e.name : 'Alguien';
        if (payload.kind === 'wave') toast(`${who} te saluda`);
        if (payload.kind === 'fist') { toast(`🤜🤛 ${who} te la choca`); const me2 = plaza.ents.get(state.user.id); if (me2) me2.emote = { kind: 'fistback', until: performance.now() + 2600 }; haptic(20); }
      }
    })
    .subscribe((status) => { if (status === 'SUBSCRIBED') plzTrack(); });
  try { localStorage.setItem('ub_plaza_room', id); } catch (_) {}
}

function plzTrack() {
  if (!plaza || !plaza.chan) return;
  const me = plaza.me;
  try { plaza.chan.track({ username: me.username, name: me.name, avatar_url: state.profile.avatar_url, accent: me.accent, hat: me.hat, i: Math.round(me.x), j: Math.round(me.y) }); } catch (_) {}
}

function plzSyncRoster(st) {
  const seen = new Set();
  for (const [uid, metas] of Object.entries(st)) {
    if (isHidden(uid)) continue;
    seen.add(uid);
    const meta = metas[metas.length - 1] || {};
    let e = plaza.ents.get(uid);
    if (!e) { e = plzEntity(meta, uid); plaza.ents.set(uid, e); }
    else if (uid !== state.user.id) { if (!e.path.length) { e.x = meta.i ?? e.x; e.y = meta.j ?? e.y; } if (meta.accent) e.accent = meta.accent; if (meta.hat) e.hat = meta.hat; }
  }
  // quitar a quien ya no está — PERO nunca a mí mismo (mi presencia puede tardar en sincronizar)
  for (const uid of [...plaza.ents.keys()]) if (uid !== state.user.id && !seen.has(uid)) plaza.ents.delete(uid);
  const n = $('plazaLiveN'); if (n) n.textContent = String(plaza.ents.size);
}

async function renderPlaza() {
  setActiveNav('plaza');
  const main = $('main');
  main.innerHTML = `
    <div class="plaza-view">
    <div class="main-head plaza-head">
      <div class="plaza-head-title"><h2 id="plazaRoomName">La Plaza</h2><div class="sub" id="plazaRoomSub">Pasea, saluda y conecta con la escena</div></div>
      <div class="plaza-head-actions">
        <button class="coins-chip" id="coinsChip" title="Tus monedas · toca para la tienda" aria-label="Monedas"><span class="coin"></span><b id="coinsChipN">${plzCoins()}</b></button>
        <span class="plaza-live" title="Personas aquí ahora"><span class="dot-online"></span> <b id="plazaLiveN">1</b></span>
        <div class="plaza-zoombar" id="plazaZoomBar">
          <button id="plzZoomOut" title="Alejar" aria-label="Alejar"><svg fill="none" stroke="currentColor"><use href="#i-zoom-out"/></svg></button>
          <button id="plzZoomRst" title="Ajustar" aria-label="Ajustar"><svg fill="none" stroke="currentColor"><use href="#i-fit"/></svg></button>
          <button id="plzZoomIn" title="Acercar" aria-label="Acercar"><svg fill="none" stroke="currentColor"><use href="#i-zoom-in"/></svg></button>
        </div>
        <button class="plaza-dj" id="plazaDj" title="Poner música para la plaza"><svg fill="none" stroke="currentColor"><use href="#i-headphones"/></svg><span>DJ</span></button>
      </div>
    </div>
    <div class="plaza-wrap" id="plazaWrap">
      <canvas class="plaza-canvas" id="plazaCanvas"></canvas>
      <div class="plaza-np hidden" id="plazaNp"></div>
      <div class="plaza-menu hidden" id="plazaMenu"></div>
      <div class="plaza-react-tray hidden" id="plazaReactTray"></div>
    </div>
    <div class="plaza-dock">
      <div class="plaza-bar" id="plazaBar">
        <button class="pbar-btn" data-act="dance"><svg fill="none" stroke="currentColor"><use href="#i-music"/></svg><span>Bailar</span></button>
        <button class="pbar-btn" data-act="wave"><svg fill="none" stroke="currentColor"><use href="#i-hand"/></svg><span>Saludar</span></button>
        <button class="pbar-btn" data-act="react"><svg fill="none" stroke="currentColor"><use href="#i-smile"/></svg><span>Reacción</span></button>
        <button class="pbar-btn" data-act="custom"><svg fill="none" stroke="currentColor"><use href="#i-palette"/></svg><span>Estilo</span></button>
      </div>
      <form class="plaza-chat" id="plazaChat">
        <input type="text" id="plazaMsg" maxlength="140" placeholder="Di algo a la plaza…" autocomplete="off" />
        <button class="btn primary plaza-send" type="submit" aria-label="Enviar"><svg fill="none" stroke="#fff"><use href="#i-send"/></svg></button>
      </form>
    </div>
    <div class="plaza-hint">Toca el suelo para caminar · toca a alguien para saludar o ver su perfil · usa la barra para bailar, reaccionar o cambiar tu estilo</div>
    </div>`;

  const canvas = $('plazaCanvas'), ctx = canvas.getContext('2d');
  let radioChan = null;
  // sala de inicio (la última visitada) y su posición
  let startRoom = 'plaza';
  try { const r = localStorage.getItem('ub_plaza_room'); if (r && PLZ_ROOMS[r]) startRoom = r; } catch (_) {}
  let si = 5, sj = 6;
  try { const s = JSON.parse(localStorage.getItem('ub_plaza_pos_' + startRoom) || 'null'); if (s) { si = s.i; sj = s.j; } } catch (_) {}

  const me = plzEntity({
    username: state.profile.username, name: state.profile.display_name || state.profile.username,
    avatar_url: state.profile.avatar_url, accent: (state.profile.theme && state.profile.theme.accent) || '#3e57fc',
    hat: (state.profile.theme && state.profile.theme.plaza_hat) || 'none',
    i: si, j: sj,
  }, state.user.id);

  // resolución de arte fija (los píxeles gordos los pone CSS al escalar)
  const artW = (PLZ.COLS + PLZ.ROWS) * PLZ.TW / 2 + PLZ.PADX * 2;
  const artH = (PLZ.COLS + PLZ.ROWS) * PLZ.TH / 2 + PLZ.PADT + PLZ.PADB;
  canvas.width = artW; canvas.height = artH;
  ctx.imageSmoothingEnabled = false;
  plaza = { canvas, ctx, ents: new Map([[state.user.id, me]]), me, raf: 0, last: performance.now(), target: null, ox: artW / 2, oy: PLZ.PADT, floor: null, chan: null, roomId: startRoom };

  // catálogo de objetos custom (para colisión, asientos y render) antes de entrar
  await plzLoadCustomItems();
  // canal de conteo (badge) + entrar en la sala inicial
  initPlazaWatch();
  try { plazaChan.track({ room: startRoom }); } catch (_) {}   // aparece en el conteo del mundo
  plzJoinRoom(startRoom, si, sj);

  // ---- emotes (saludo, baile, reacciones, chocarla) ----
  const sendEmote = (kind, emoji, target) => {
    const payload = { id: state.user.id, kind, emoji: emoji || null, target: target || null };
    if (kind === 'react') {
      const t = target ? plaza.ents.get(target) : me;
      if (t) t.float = { emoji, until: performance.now() + 2600 };
    } else {
      me.emote = { kind, until: performance.now() + (kind === 'dance' ? 12000 : 2600), target };
    }
    try { plaza.chan.send({ type: 'broadcast', event: 'emote', payload }); } catch (_) {}
  };

  // ---- menú al tocar un avatar ----
  const menuEl = $('plazaMenu');
  const closeMenu = () => menuEl.classList.add('hidden');
  const openMenu = (ent, cssX, cssY) => {
    const self = ent.id === state.user.id;
    menuEl.innerHTML = `
      <div class="pm-head">${esc(ent.name)}</div>
      ${self ? `
        <button data-a="dance"><svg fill="none" stroke="currentColor"><use href="#i-music"/></svg>Bailar</button>
        <button data-a="wave"><svg fill="none" stroke="currentColor"><use href="#i-hand"/></svg>Saludar</button>` : `
        <button data-a="profile"><svg fill="none" stroke="currentColor"><use href="#i-people"/></svg>Ver perfil</button>
        <button data-a="dm"><svg fill="none" stroke="currentColor"><use href="#i-comment"/></svg>Mensaje</button>
        <button data-a="wave"><svg fill="none" stroke="currentColor"><use href="#i-hand"/></svg>Saludar</button>
        <button data-a="fist"><svg fill="none" stroke="currentColor"><use href="#i-hand"/></svg>Chocarla</button>`}
      <div class="pm-row">
        <button data-a="react" data-e="❤️">❤️</button>
        <button data-a="react" data-e="🔥">🔥</button>
        <button data-a="react" data-e="😂">😂</button>
        <button data-a="react" data-e="🫡">🫡</button>
      </div>`;
    const wrap = $('plazaWrap');
    menuEl.classList.remove('hidden');
    const mw = menuEl.offsetWidth || 150, mh = menuEl.offsetHeight || 160;
    menuEl.style.left = Math.max(6, Math.min(cssX - mw / 2, wrap.clientWidth - mw - 6)) + 'px';
    menuEl.style.top = Math.max(6, Math.min(cssY - mh - 14, wrap.clientHeight - mh - 6)) + 'px';
    menuEl.querySelectorAll('button').forEach(b => b.onclick = (ev) => {
      ev.stopPropagation(); closeMenu(); haptic(10);
      const a = b.dataset.a;
      if (a === 'profile') openProfile(ent.id);
      else if (a === 'dm') openDM(ent.id);
      else if (a === 'dance') sendEmote('dance');
      else if (a === 'wave') sendEmote('wave', null, self ? null : ent.id);
      else if (a === 'fist') sendEmote('fist', null, ent.id);
      else if (a === 'react') sendEmote('react', b.dataset.e, self ? null : ent.id);
    });
  };
  // ---- menú al tocar un objeto de tu sala en modo edición ----
  const objIco = (name) => `<svg fill="none" stroke="currentColor"><use href="#i-${name}"/></svg>`;
  const openObjMenu = (f, cssX, cssY) => {
    const name = PLZ_ITEM_NAME[f.t] || f.t;
    menuEl.innerHTML = `<div class="pm-head">${esc(name)}</div>
      <button data-a="move">${objIco('tools')}Mover</button>
      <button data-a="flip">${objIco('mirror')}Girar</button>
      <button data-a="pick">${objIco('files')}Recoger</button>
      <button data-a="sell" class="pm-sell">${objIco('cart')}Vender</button>`;
    menuEl.classList.remove('hidden');
    const mw = menuEl.offsetWidth || 150, mh = menuEl.offsetHeight || 160;
    menuEl.style.left = Math.max(6, Math.min(cssX - mw / 2, $('plazaWrap').clientWidth - mw - 6)) + 'px';
    menuEl.style.top = Math.max(6, Math.min(cssY - mh - 14, $('plazaWrap').clientHeight - mh - 6)) + 'px';
    menuEl.querySelectorAll('button').forEach(b => b.onclick = (ev) => {
      ev.stopPropagation(); closeMenu(); haptic(8);
      const a = b.dataset.a;
      if (a === 'move') { plaza.moving = f; toast('Toca dónde colocarlo'); }
      else if (a === 'flip') { f.flip = !f.flip; haptic(6); }
      else if (a === 'pick') plzPickFurn(f);
      else if (a === 'sell') plzSellFurn(f);
    });
  };
  document.addEventListener('pointerdown', function pmOut(e) {
    if (!plaza) { document.removeEventListener('pointerdown', pmOut); return; }
    if (!menuEl.contains(e.target) && e.target !== canvas) closeMenu();
  });

  // ---- tocar el lienzo: avatar → menú; suelo → caminar ----
  canvas.addEventListener('pointerdown', (e) => {
    const r = canvas.getBoundingClientRect();
    const s = r.width / canvas.width;
    const rx = (e.clientX - r.left) / s - plaza.ox, ry = (e.clientY - r.top) / s - plaza.oy;
    closeMenu();
    // modo edición de sala: colocar/quitar objetos, o abrir el menú de un objeto ya puesto
    if (plaza.editing) {
      const efi = Math.floor((rx / (PLZ.TW / 2) + ry / (PLZ.TH / 2)) / 2);
      const efj = Math.floor((ry / (PLZ.TH / 2) - rx / (PLZ.TW / 2)) / 2);
      if (plaza.moving) { plzMoveTo(plaza.moving, efi, efj); plaza.moving = null; return; }   // recolocar
      // hit-test del sprite visible (de delante hacia atrás): permite tocar el objeto donde SE VE,
      // no solo su casilla del suelo (los muebles altos se dibujan por encima de su baldosa).
      const hitF = [...plzR.furn].filter(f => f.t !== 'portal').sort((a, b) => (b.i + b.j) - (a.i + a.j))
        .find(f => { const bx = plzFurnHitBox(f); return rx >= bx.x0 && rx <= bx.x1 && ry >= bx.y0 && ry <= bx.y1; });
      if (plaza.editTool === 'erase') {   // quitar: el objeto tocado o el de la casilla
        let t = hitF; if (!t) { const k = plzFindFurnAt(plzR.furn, efi, efj); if (k >= 0) t = plzR.furn[k]; }
        if (t) plzPickFurn(t); else toast('Toca un objeto para quitarlo');
        return;
      }
      if (hitF) { openObjMenu(hitF, (e.clientX - r.left), (e.clientY - r.top)); haptic(6); return; }   // menú del objeto
      plzEditTap(efi, efj); return;   // suelo vacío → colocar el objeto elegido
    }
    // ¿ha tocado el objeto interactivo de la sala? → abre su minijuego
    const act = PLZ_ACTIVITY[plaza.roomId];
    if (act) {
      const w = act.w || 12, top = act.top || 40, bot = act.bot || 4;
      const spot = plzR.furn.find(f => {
        if (f.t !== act.furn) return false;
        const p2 = plzIso(f.i, f.j), bx2 = p2.x, base2 = p2.y + PLZ.TH / 2;
        return rx >= bx2 - w && rx <= bx2 + w && ry >= base2 - top && ry <= base2 + bot;
      });
      if (spot) { haptic(12); act.open(); return; }
    }
    // ¿ha tocado un avatar? (los de delante tienen prioridad)
    const hit = [...plaza.ents.values()].sort((a, b) => (b.x + b.y) - (a.x + a.y)).find(en => {
      const p2 = plzIso(en.x, en.y); const bx2 = p2.x, base2 = p2.y + PLZ.TH / 2;
      return rx >= bx2 - 11 && rx <= bx2 + 11 && ry >= base2 - 46 && ry <= base2 + 3;
    });
    if (hit) { openMenu(hit, (e.clientX - r.left), (e.clientY - r.top)); haptic(6); return; }
    const fi = Math.floor((rx / (PLZ.TW / 2) + ry / (PLZ.TH / 2)) / 2);
    const fj = Math.floor((ry / (PLZ.TH / 2) - rx / (PLZ.TW / 2)) / 2);
    if (!plzFree(fi, fj)) return;
    // asiento ocupado por otra persona → no se puede
    if (plzR.seats.has(plzKey(fi, fj))) {
      for (const o of plaza.ents.values()) {
        if (o.id !== state.user.id && !o.path.length && Math.round(o.x) === fi && Math.round(o.y) === fj) { toast('Ese sitio está ocupado 😅'); return; }
      }
    }
    const from = { i: Math.round(me.x), j: Math.round(me.y) };
    const path = plzPath(from, { i: fi, j: fj });
    if (!path || !path.length) return;
    me.path = path; plaza.target = { i: fi, j: fj, t0: performance.now() };
    me.emote = null;   // caminar corta el baile
    haptic(8);
    try { plaza.chan.send({ type: 'broadcast', event: 'move', payload: { id: state.user.id, from, path } }); } catch (_) {}
  });

  // === EL BUCLE ARRANCA YA (antes que nada opcional): moverse siempre funciona ===
  const loop = (now) => {
    if (!plaza || !canvas.isConnected) { plzLeave(); return; }
    const dt = Math.min((now - plaza.last) / 1000, 0.1); plaza.last = now;
    try { for (const e of plaza.ents.values()) plzStep(e, dt, e === me); plzDraw(now); } catch (_) {}
    plaza.raf = requestAnimationFrame(loop);
  };
  plaza.raf = requestAnimationFrame(loop);

  // ---- barra de acciones (junto al chat) ----
  try {
    const tray = $('plazaReactTray');
    const REACTS = ['❤️', '🔥', '😂', '🫡', '😮', '👏', '💜', '😎', '🥶', '🤝'];
    tray.innerHTML = REACTS.map(e => `<button data-e="${e}">${e}</button>`).join('');
    tray.querySelectorAll('button').forEach(b => b.onclick = () => { sendEmote('react', b.dataset.e); tray.classList.add('hidden'); haptic(8); });
    $('plazaBar').querySelectorAll('.pbar-btn').forEach(b => b.onclick = () => {
      const a = b.dataset.act; haptic(8);
      if (a === 'dance') { const on = me.emote && me.emote.kind === 'dance'; if (on) { me.emote = null; sendEmote('idle'); } else sendEmote('dance'); b.classList.toggle('on', !on); }
      else if (a === 'wave') sendEmote('wave');
      else if (a === 'react') tray.classList.toggle('hidden');
      else if (a === 'custom') openPlazaCustomizer(() => { const th = state.profile.theme || {}; if (th.accent) me.accent = th.accent; me.hat = th.plaza_hat || 'none'; try { plzTrack(); } catch (_) {} });
    });
  } catch (err) { console.warn('plaza bar', err); }

  // hablar
  try {
    $('plazaChat').addEventListener('submit', (e) => {
      e.preventDefault();
      if (!requireNotBanned()) return;
      const inp = $('plazaMsg'); const text = inp.value.trim(); if (!text) return;
      inp.value = '';
      me.bubble = { text: text.slice(0, 140), until: performance.now() + 6500 };
      try { plaza.chan.send({ type: 'broadcast', event: 'chat', payload: { id: state.user.id, text: text.slice(0, 140) } }); } catch (_) {}
    });
  } catch (_) {}

  // ---- radio de la Plaza: todos escuchan la misma pista sincronizada (opcional) ----
  plaza.radio = { playing: false, trackId: null };
  const npEl = $('plazaNp');
  const updNp = (t, byName) => {
    if (!t) {
      npEl.classList.add('hidden');
      if (plaza.radio.playing && plaza.radio.trackId && state.current && state.current.id === plaza.radio.trackId) { try { audio.pause(); } catch (_) {} }
      plaza.radio.playing = false; plaza.radio.trackId = null; return;
    }
    plaza.radio.playing = true; plaza.radio.trackId = t.id;
    npEl.innerHTML = `<span class="np-eq"><i></i><i></i><i></i></span> <b>${esc(t.title || 'Pista')}</b>${byName ? ` <span>· la puso ${esc(byName)}</span>` : ''}<button class="np-stop" title="Quitar la música">✕</button>`;
    npEl.classList.remove('hidden');
    const st = npEl.querySelector('.np-stop'); if (st) st.onclick = stopPlazaRadio;
  };
  const stopPlazaRadio = async () => {
    try { await sb.from('plaza_radio').update({ track_id: null, started_at: null, set_by: null }).eq('id', 1); toast('Música quitada'); updNp(null); } catch (_) { toast('No se pudo quitar'); }
  };
  const applyRadio = async (row) => {
    try {
      if (!row || !row.track_id || !row.started_at) { updNp(null); return; }
      const { data: t } = await sb.from('tracks').select('*, profiles!tracks_user_id_fkey(*)').eq('id', row.track_id).maybeSingle();
      if (!t || !plaza) return;
      let byName = '';
      if (row.set_by) { try { const { data: p2 } = await sb.from('profiles').select('username,display_name').eq('id', row.set_by).maybeSingle(); byName = p2 ? (p2.display_name || p2.username) : ''; } catch (_) {} }
      updNp(t, byName);
      const offset = Math.max(0, (Date.now() - new Date(row.started_at).getTime()) / 1000);
      if (!state.current || state.current.id !== t.id) {
        playTrack(t);
        const seek = () => { try { const d = audio.duration || t.duration || 0; audio.currentTime = d > 2 ? (offset % d) : 0; } catch (_) {} };
        if (audio.readyState >= 1) seek(); else audio.addEventListener('loadedmetadata', seek, { once: true });
      }
    } catch (_) {}
  };
  try {
    radioChan = sb.channel('plaza-radio-db')
      .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'plaza_radio' }, (p) => { if (plaza) applyRadio(p.new); })
      .subscribe();
    sb.from('plaza_radio').select('*').eq('id', 1).maybeSingle().then(({ data }) => { if (plaza) applyRadio(data); });
    $('plazaDj').onclick = () => openPlazaTrackPicker(async (t) => {
      if (t === '__stop__') { stopPlazaRadio(); return; }
      const { error } = await sb.from('plaza_radio').update({ track_id: t.id, started_at: new Date().toISOString(), set_by: state.user.id }).eq('id', 1);
      if (error) { toast('No se pudo poner la música'); return; }
      toast('Pinchando para toda la plaza');
      sendEmote('react', '🎶');
    }, plaza.radio.playing);
  } catch (err) { console.warn('plaza radio', err); }

  // monedas: visibles solo dentro de la plaza y sus salas
  { const cc = $('coinsChip'); if (cc) cc.onclick = () => openPlazaShop(); }
  plzUpdateCoinsHub();

  // zoom del mundo (solo escritorio): escala uniforme del lienzo, el mapeo de clics
  // se mantiene correcto porque usa getBoundingClientRect. Se navega con el scroll.
  let pzoom = 1;
  const wrapEl = $('plazaWrap');
  const applyZoom = () => {
    if (!wrapEl || !canvas) return;
    const desktop = window.innerWidth >= 721;
    if (!desktop || pzoom <= 1.01) { canvas.style.height = ''; canvas.style.width = ''; canvas.style.maxWidth = ''; wrapEl.classList.remove('plaza-zoomed'); pzoom = Math.max(1, pzoom); return; }
    wrapEl.classList.add('plaza-zoomed');
    const baseH = wrapEl.clientHeight; canvas.style.height = Math.round(baseH * pzoom) + 'px'; canvas.style.width = 'auto'; canvas.style.maxWidth = 'none';
  };
  const setZoom = (z) => { pzoom = Math.max(1, Math.min(3, z)); applyZoom(); };
  { const zi = $('plzZoomIn'), zo = $('plzZoomOut'), zr = $('plzZoomRst');
    if (zi) zi.onclick = () => setZoom(pzoom + 0.35);
    if (zo) zo.onclick = () => setZoom(pzoom - 0.35);
    if (zr) zr.onclick = () => setZoom(1); }
  canvas.addEventListener('wheel', (e) => { if (window.innerWidth < 721) return; e.preventDefault(); setZoom(pzoom + (e.deltaY < 0 ? 0.3 : -0.3)); }, { passive: false });

  function plzLeave() {
    try { plazaChan.untrack(); } catch (_) {}                                  // salir del conteo del mundo
    try { plaza.chan.untrack(); sb.removeChannel(plaza.chan); } catch (_) {}    // salir de la sala
    try { sb.removeChannel(radioChan); } catch (_) {}
    try { closeMenu(); } catch (_) {}
    try { localStorage.setItem('ub_plaza_pos_' + plaza.roomId, JSON.stringify({ i: Math.round(me.x), j: Math.round(me.y) })); } catch (_) {}
    plaza = null;
  }

  function plzStep(e, dt, isMe) {
    if (!e.path.length) return;
    const t = e.path[0];
    const dx = t.i - e.x, dy = t.j - e.y;
    const dist = Math.hypot(dx, dy), step = PLZ.SPEED * dt;
    if (dist <= step) {
      e.x = t.i; e.y = t.j; e.path.shift();
      if (isMe && !e.path.length) {
        const portal = plzR.portals.get(plzKey(t.i, t.j));
        if (portal) {
          if (portal.to === '__rooms__') { openPlazaRoomsBrowser(); plzTrack(); return; }
          toast('Entrando en ' + (PLZ_ROOMS[portal.to] ? PLZ_ROOMS[portal.to].name : '…'));
          plzJoinRoom(portal.to, portal.spawn[0], portal.spawn[1]); return;
        }
        plzTrack();
        try { localStorage.setItem('ub_plaza_pos_' + plaza.roomId, JSON.stringify({ i: t.i, j: t.j })); } catch (_) {}
      }
    } else { e.x += dx / dist * step; e.y += dy / dist * step; }
  }
}

function plzIso(x, y) { return { x: (x - y) * PLZ.TW / 2, y: (x + y) * PLZ.TH / 2 }; }

// personalizador del avatar de la Plaza (color + accesorio, con vista previa)
function openPlazaCustomizer(onChange) {
  const COLORS = ['#3e57fc', '#27a9ff', '#6e2df5', '#e0507a', '#2dc878', '#f0a13e', '#ff5d5d', '#12c2c2', '#b06eff', '#ffd23e', '#8f99ad', '#111827'];
  let curAccent = (state.profile.theme && state.profile.theme.accent) || '#3e57fc';
  let curHat = (state.profile.theme && state.profile.theme.plaza_hat) || 'none';
  const m = openModal(`<div class="modal-head"><h3><svg class="mh-ic" fill="none" stroke="currentColor"><use href="#i-palette"/></svg> Personaliza tu avatar</h3><button class="close">&times;</button></div>
    <div class="modal-body">
      <div class="pcz-preview"><canvas id="pczCanvas" width="44" height="64"></canvas></div>
      <div class="pcz-sec"><div class="pcz-lbl">Color</div>
        <div class="pcz-grid" id="pczGrid">${COLORS.map(col => `<button class="pcz-sw ${col === curAccent ? 'on' : ''}" data-c="${col}" style="background:${col}" aria-label="Color"></button>`).join('')}</div>
      </div>
      <div class="pcz-sec"><div class="pcz-lbl">Accesorio</div>
        <div class="pcz-hats" id="pczHats">${PLZ_HATS.map(h => `<button class="pcz-hat ${h === curHat ? 'on' : ''}" data-h="${h}">${PLZ_HAT_NAMES[h]}</button>`).join('')}</div>
      </div>
    </div>`);
  const pc = m.querySelector('#pczCanvas'), pctx = pc.getContext('2d'); pctx.imageSmoothingEnabled = false;
  const PW = 44, PH = 64; let prevImg = null, prevOk = false;
  if (state.profile.avatar_url) { const im = new Image(); im.crossOrigin = 'anonymous'; im.onload = () => { prevImg = im; prevOk = true; drawPreview(); }; im.src = czUrl(state.profile.avatar_url); }
  function drawPreview() {
    pctx.clearRect(0, 0, PW, PH);
    const e = { accent: curAccent, hat: curHat, name: state.profile.display_name || state.profile.username || '?', img: prevImg, imgOk: prevOk };
    const cx = Math.round(PW / 2), by = PH - 28;
    pctx.fillStyle = 'rgba(0,0,0,.3)'; pctx.beginPath(); pctx.ellipse(cx, PH - 8, 12, 4, 0, 0, 7); pctx.fill();
    plzRect(pctx, cx - 5, by + 12, 4, 8, '#10142a', '#05070f'); plzRect(pctx, cx + 1, by + 12, 4, 8, '#10142a', '#05070f');
    plzRect(pctx, cx - 7, by, 14, 13, e.accent, '#05070f'); pctx.fillStyle = 'rgba(255,255,255,.22)'; pctx.fillRect(cx - 7, by, 14, 2);
    plzRect(pctx, cx - 10, by + 1, 3, 9, e.accent, '#05070f'); plzRect(pctx, cx + 7, by + 1, 3, 9, e.accent, '#05070f');
    const hs = 14, hx = cx - hs / 2, hy = by - hs - 1;
    plzRect(pctx, hx, hy, hs, hs, '#1a2138', '#05070f');
    if (e.imgOk) { try { pctx.drawImage(e.img, hx + 1, hy + 1, hs - 2, hs - 2); } catch (_) {} }
    else { pctx.fillStyle = e.accent; pctx.fillRect(hx + 1, hy + 1, hs - 2, hs - 2); pctx.fillStyle = '#fff'; pctx.font = '700 9px monospace'; pctx.textAlign = 'center'; pctx.textBaseline = 'middle'; pctx.fillText((e.name || '?').slice(0, 1).toUpperCase(), cx, hy + hs / 2 + 1); }
    if (e.hat !== 'none') plzDrawHat(pctx, e, cx, hx, hy, hs, performance.now());
  }
  drawPreview();
  const save = async () => {
    const theme = Object.assign({}, state.profile.theme || {}, { accent: curAccent, plaza_hat: curHat });
    state.profile.theme = theme;
    try { await sb.from('profiles').update({ theme }).eq('id', state.user.id); } catch (_) {}
    onChange && onChange();
  };
  m.querySelectorAll('.pcz-sw').forEach(b => b.onclick = () => { curAccent = b.dataset.c; m.querySelectorAll('.pcz-sw').forEach(x => x.classList.toggle('on', x === b)); haptic(6); drawPreview(); save(); });
  m.querySelectorAll('.pcz-hat').forEach(b => b.onclick = () => { curHat = b.dataset.h; m.querySelectorAll('.pcz-hat').forEach(x => x.classList.toggle('on', x === b)); haptic(6); drawPreview(); save(); });
}

// ===================== SALAS DE USUARIO: explorar, visitar y editar =====================
