      const t = 0.5 + s * 0.28; if (t > 34) break;
      const long = s % 9 === 4;
      if (s % 2 === 0) { let l = (s * 3 + (s >> 2)) % 4; if (l === prev) l = (l + 1) % 4; prev = l; chart.push({ lane: l, t, dur: long ? 1.1 : 0, hit: false, done: false, holding: false }); }
