      if (bd < 0.05) { pts = 300; txt = 'PERFECT'; col = '#ffd23e'; }
      else if (bd < 0.10) { pts = 200; txt = 'GREAT'; col = '#2dc878'; }
      else { pts = 100; txt = 'GOOD'; col = '#27a9ff'; }
