// Selector: ¿subir una pista o una foto?
function openCreateChooser() {
  if (!requireNotBanned()) return;
  const m = openModal(`
    <div class="modal-head"><h3>¿Qué quieres compartir?</h3><button class="close">&times;</button></div>
    <div class="modal-body">
      <div class="create-choices">
        <button class="create-choice" id="chTrack"><span class="cc-ic"><svg fill="none" stroke="#fff"><use href="#i-music"/></svg></span><b>Pista</b><span class="cc-sub">Sube una canción o beat</span></button>
        <button class="create-choice" id="chAlbum"><span class="cc-ic"><svg fill="none" stroke="#fff"><use href="#i-headphones"/></svg></span><b>Álbum / EP</b><span class="cc-sub">Sube o agrupa varias pistas</span></button>
        <button class="create-choice" id="chPhoto"><span class="cc-ic"><svg fill="none" stroke="#fff"><use href="#i-camera"/></svg></span><b>Foto</b><span class="cc-sub">Publica una imagen</span></button>
      </div>
    </div>`);
  m.querySelector('#chTrack').onclick = () => { m.remove(); openUploadModal(); };
  m.querySelector('#chAlbum').onclick = () => { m.remove(); openAlbumModal(); };
  m.querySelector('#chPhoto').onclick = () => { m.remove(); openPhotoUploadModal(); };
}

// Sube un audio suelto para un álbum (aislado del subidor principal para no tocar el core).
// Reutiliza compresión y waveform si están disponibles.
async function uploadAlbumTrack(file, opts, onProgress) {
  const uid = state.user.id;
  const stamp = Date.now() + '-' + Math.random().toString(36).slice(2, 8);
  const LIMIT = 50 * 1024 * 1024;
  let uploadFile = file;
  const ext0 = (file.name.split('.').pop() || '').toLowerCase();
  const lossless = /^(wav|flac|aiff|aif|alac)$/.test(ext0);   // formatos sin pérdida → siempre comprimir
  const heavy = file.size > 16 * 1024 * 1024;                 // pesado (probable alta tasa o larga)
  const tooBig = file.size > 45 * 1024 * 1024;
  if (tooBig || lossless || heavy) await ensureLamejs();
  if (window.lamejs && (tooBig || lossless || heavy)) {
    try {
      uploadFile = await compressAudioToMp3(file, tooBig ? 192 : 160, (p) => onProgress && onProgress(p * 0.5));
      if (uploadFile.size > LIMIT) uploadFile = await compressAudioToMp3(file, 128, () => {});
    } catch (_) { uploadFile = file; }
    // si la versión MP3 no ahorró y el original cabía, conserva el original
    if (!tooBig && uploadFile.size >= file.size && file.size <= LIMIT) uploadFile = file;
  }
  if (uploadFile.size > LIMIT) throw new Error('“' + file.name + '” es demasiado grande.');
  const ext = (uploadFile.name.split('.').pop() || 'mp3').toLowerCase();
  const AUDIO_MIME = { mp3: 'audio/mpeg', wav: 'audio/wav', m4a: 'audio/mp4', aac: 'audio/aac', flac: 'audio/flac', ogg: 'audio/ogg', oga: 'audio/ogg', opus: 'audio/opus', aif: 'audio/aiff', aiff: 'audio/aiff', wma: 'audio/x-ms-wma', alac: 'audio/mp4' };
  const audioUrl = await uploadMedia('tracks', uploadFile, null, uploadFile.type || AUDIO_MIME[ext] || 'audio/mpeg');
  let waveform = null; try { waveform = await computeWaveformPeaks(uploadFile); } catch (_) {}
  // medir la duración del audio (antes se referenciaba una variable inexistente y el álbum entero fallaba)
  let duration = 0;
  try {
    duration = await new Promise((res) => {
      const u = URL.createObjectURL(uploadFile); const a = new Audio();
      const done = (d) => { try { URL.revokeObjectURL(u); } catch (_) {} res(d); };
      a.onloadedmetadata = () => done(a.duration || 0);
      a.onerror = () => done(0);
      setTimeout(() => done(0), 10000);
      a.src = u;
    });
  } catch (_) {}
  const payload = {
    user_id: uid, title: opts.title, genre: opts.genre || null,
    artist: state.profile.display_name || state.profile.username,
    audio_url: audioUrl, cover_url: opts.coverUrl || null, duration: Math.round(duration || 0),
    waveform, album_id: opts.album_id, album_pos: opts.album_pos,
  };
  let { error } = await sb.from('tracks').insert(payload);
  if (error && /album_id|album_pos|column/i.test(error.message || '')) { delete payload.album_id; delete payload.album_pos; ({ error } = await sb.from('tracks').insert(payload)); }
  if (error) throw error;
}

function openAlbumModal() {
  if (!requireNotBanned()) return;
  const m = openModal(`
    <div class="modal-head"><h3>Nuevo álbum / EP</h3><button class="close">&times;</button></div>
    <div class="modal-body">
      <div class="field"><label>Título del álbum</label><input type="text" id="alTitle" maxlength="80" placeholder="Nombre del álbum o EP" /></div>
      <div class="field"><label>Género <span style="color:var(--ink-faint);font-weight:400">(por defecto para las pistas)</span></label><input type="text" id="alGenre" placeholder="Trap, Drill, R&B…" /></div>
      <div class="field"><label>Descripción <span style="color:var(--ink-faint);font-weight:400">(opcional)</span></label><textarea id="alDesc" maxlength="600" placeholder="Cuéntale a la gente de qué va este álbum…"></textarea></div>
      <div class="field"><label>Tipo</label>
        <select id="alKind" class="up-select"><option value="album">Álbum</option><option value="ep">EP</option><option value="mixtape">Mixtape</option></select>
      </div>
      <div class="field">
        <label>Portada <span style="color:var(--ink-faint);font-weight:400">(opcional)</span></label>
        <div class="cover-pick" id="alDzCover"><div class="cover-prev" id="alCoverPrev"><svg width="24" height="24" fill="none" stroke="currentColor"><use href="#i-image"/></svg></div><div class="cover-pick-txt"><b id="alCoverName">Añadir portada</b><span>Imagen cuadrada</span></div></div>
        <input type="file" id="alFCover" accept="image/*" hidden />
      </div>
      <div class="field">
        <label>Subir audios nuevos <span style="color:var(--ink-faint);font-weight:400">(puedes elegir varios)</span></label>
        <div class="dropzone" id="alDzAudio"><svg fill="none"><use href="#i-upload"/></svg><div>Arrastra tus MP3/WAV o haz clic</div></div>
        <input type="file" id="alFAudio" accept="audio/*,.mp3,.wav,.m4a,.aac,.flac,.ogg,.oga,.opus,.aif,.aiff,.wma,.alac" multiple hidden />
        <div id="alTrackRows" class="al-trackrows"></div>
      </div>
      <div class="field" id="alExistingWrap">
        <label>O añade pistas que ya tienes</label>
        <div id="alExisting" class="al-existing"><div class="sub" style="padding:8px">Cargando tus pistas…</div></div>
      </div>
      <div class="progress-bar hidden" id="alBar"><div></div></div>
      <button class="btn primary" id="alSubmit"><svg stroke="#fff"><use href="#i-headphones"/></svg> Crear álbum</button>
      <div class="auth-msg" id="alMsg"></div>
    </div>`);

  let coverFile = null, audioFiles = [];
  const fCover = m.querySelector('#alFCover'), dzCover = m.querySelector('#alDzCover');
  dzCover.onclick = () => fCover.click();
  fCover.onchange = () => { const f = fCover.files[0]; if (!f || !f.type.startsWith('image')) return; coverFile = f; m.querySelector('#alCoverName').textContent = f.name; m.querySelector('#alCoverPrev').innerHTML = `<img decoding="async" src="${URL.createObjectURL(f)}" alt="" />`; };
  const fAudio = m.querySelector('#alFAudio'), dzAudio = m.querySelector('#alDzAudio');
  const rowsBox = m.querySelector('#alTrackRows');
  dzAudio.onclick = () => fAudio.click();
  // Renderiza una fila editable por audio: título (autorrellenado) + género
  const renderRows = () => {
    rowsBox.innerHTML = audioFiles.map((f, i) => `
      <div class="al-trow">
        <span class="al-trow-i">${i + 1}</span>
        <div class="al-trow-fields">
          <input class="al-trow-title" data-i="${i}" maxlength="100" value="${esc(f.name.replace(/\.[^.]+$/, ''))}" placeholder="Título de la pista" />
          <input class="al-trow-genre" data-i="${i}" maxlength="40" placeholder="Género (opcional)" />
        </div>
        <button type="button" class="al-trow-x" data-i="${i}" aria-label="Quitar">&times;</button>
      </div>`).join('');
    rowsBox.querySelectorAll('.al-trow-x').forEach(b => b.onclick = () => { audioFiles.splice(+b.dataset.i, 1); renderRows(); });
  };
  const addFiles = (files) => {
    const ok = files.filter(f => /audio|\.(mp3|wav|m4a|aac|flac|ogg|oga|opus|aif|aiff|wma|alac)$/i.test((f.type || '') + f.name));
    if (ok.length) { audioFiles = audioFiles.concat(ok); renderRows(); }
  };
  fAudio.onchange = () => { addFiles(Array.from(fAudio.files || [])); fAudio.value = ''; };
  ['dragover', 'dragleave', 'drop'].forEach(ev => dzAudio.addEventListener(ev, (e) => { e.preventDefault(); if (ev === 'dragover') dzAudio.classList.add('drag'); else dzAudio.classList.remove('drag'); if (ev === 'drop' && e.dataTransfer.files.length) addFiles(Array.from(e.dataTransfer.files)); }));

  // pistas existentes (sin álbum) para opción A
  (async () => {
    const { data } = await sb.from('tracks').select('id,title,cover_url').eq('user_id', state.user.id).is('album_id', null).order('created_at', { ascending: false });
    const box = m.querySelector('#alExisting');
    if (!data || !data.length) { box.innerHTML = '<div class="sub" style="padding:8px">No tienes pistas sueltas para añadir.</div>'; return; }
    box.innerHTML = data.map(t => `<label class="al-pick"><input type="checkbox" value="${t.id}" /><span class="al-pick-cov" style="${t.cover_url ? `background-image:url('${czUrl(t.cover_url)}')` : ''}"></span><span class="al-pick-t">${esc(t.title)}</span></label>`).join('');
  })();

  m.querySelector('#alSubmit').onclick = async () => {
    const msg = m.querySelector('#alMsg'); msg.className = 'auth-msg';
    const title = m.querySelector('#alTitle').value.trim();
    const genre = m.querySelector('#alGenre').value.trim();
    const description = m.querySelector('#alDesc').value.trim();
    const kind = m.querySelector('#alKind').value;
    const picked = Array.from(m.querySelectorAll('#alExisting input:checked')).map(c => c.value);
    // título/género por pista (lo que el usuario haya escrito en cada fila)
    const rowTitles = Array.from(m.querySelectorAll('.al-trow-title')).map(i => i.value.trim());
    const rowGenres = Array.from(m.querySelectorAll('.al-trow-genre')).map(i => i.value.trim());
    if (!title) { msg.className = 'auth-msg error'; msg.textContent = 'Ponle un título al álbum.'; return; }
    if (!audioFiles.length && !picked.length) { msg.className = 'auth-msg error'; msg.textContent = 'Añade al menos una pista (sube audios o elige existentes).'; return; }
    const btn = m.querySelector('#alSubmit'); btn.disabled = true;
    const bar = m.querySelector('#alBar'); bar.classList.remove('hidden'); const fill = bar.firstElementChild; fill.style.width = '8%';
    try {
      const uid = state.user.id;
      // portada del álbum
      let coverUrl = null;
      if (coverFile) {
        try { coverUrl = await uploadMedia('covers', coverFile); } catch (_) {}
      }
      // crea el álbum
      const { data: alb, error: ae } = await sb.from('albums').insert({ user_id: uid, title, description: description || null, cover_url: coverUrl, kind }).select().single();
      if (ae) throw ae;
      let pos = 0;
      // A) pistas existentes
      if (picked.length) {
        for (const id of picked) { await sb.from('tracks').update({ album_id: alb.id, album_pos: pos++ }).eq('id', id).eq('user_id', uid); }
        fill.style.width = '30%';
      }
      // B) audios nuevos
      for (let i = 0; i < audioFiles.length; i++) {
        const f = audioFiles[i];
        const tTitle = (rowTitles[i] || '').trim() || f.name.replace(/\.[^.]+$/, '');
        const tGenre = (rowGenres[i] || '').trim() || genre;
        msg.className = 'auth-msg'; msg.textContent = `Subiendo ${i + 1}/${audioFiles.length}: ${tTitle}`;
        await uploadAlbumTrack(f, { title: tTitle, genre: tGenre, coverUrl, album_id: alb.id, album_pos: pos++ }, (p) => { fill.style.width = (30 + ((i + p) / audioFiles.length) * 65) + '%'; });
      }
      // si el álbum no tiene portada, hereda la de su primera pista
      if (!coverUrl) {
        const { data: first } = await sb.from('tracks').select('cover_url').eq('album_id', alb.id).not('cover_url', 'is', null).order('album_pos').limit(1).maybeSingle();
        if (first && first.cover_url) await sb.from('albums').update({ cover_url: first.cover_url }).eq('id', alb.id);
      }
      fill.style.width = '100%';
      toast('¡Álbum creado! 🎶');
      m.remove();
      updateCounts();
      openAlbum(alb.id);
    } catch (err) {
      console.error(err);
      msg.className = 'auth-msg error'; msg.textContent = 'Error al crear el álbum: ' + (err.message || err);
      btn.disabled = false;
    }
  };
}

async function openAlbum(albumId) {
  const main = $('main');
  main.innerHTML = `<div class="loading"><div class="spinner"></div></div>`;
  const { data: alb } = await sb.from('albums').select('*, profiles:user_id(username,display_name)').eq('id', albumId).maybeSingle();
  if (!alb) { toast('Álbum no encontrado'); switchView('feed'); return; }
  const { data: trks } = await sb.from('tracks').select('*, profiles!tracks_user_id_fkey(*)').eq('album_id', albumId).order('album_pos');
  const list = trks || [];
  const mine = alb.user_id === state.user.id;
  const artist = alb.profiles?.display_name || alb.profiles?.username || '';
  const kindLabel = alb.kind === 'ep' ? 'EP' : alb.kind === 'mixtape' ? 'Mixtape' : 'Álbum';
  main.innerHTML = `
    <button class="profile-back" id="albBack"><svg fill="none" stroke="currentColor"><use href="#i-chevron-left"/></svg> Volver</button>
    <div class="album-head">
      <div class="album-head-cov" style="${alb.cover_url ? `background-image:url('${esc(czUrl(alb.cover_url))}')` : ''}">${alb.cover_url ? '' : '<svg fill="none" stroke="currentColor"><use href="#i-headphones"/></svg>'}</div>
      <div class="album-head-meta">
        <span class="album-kind">${kindLabel}</span>
        <h2>${esc(alb.title)}</h2>
        <div class="album-artist">${esc(artist)} · ${list.length} ${list.length === 1 ? 'pista' : 'pistas'}</div>
        ${alb.description ? `<p class="album-desc">${esc(alb.description).replace(/\n/g, '<br>')}</p>` : ''}
        <div class="album-actions">
          <button class="btn primary" id="albPlay"><svg fill="none" stroke="#fff"><use href="#i-play"/></svg> Reproducir</button>
          ${mine ? '<button class="btn" id="albDelete"><svg fill="none" stroke="currentColor"><use href="#i-trash"/></svg> Borrar álbum</button>' : ''}
        </div>
      </div>
    </div>
    <div id="albList" class="feed-list"></div>`;
  $('albBack').onclick = () => openProfile(alb.user_id);
  const lc = $('albList');
  if (!list.length) lc.innerHTML = `<div class="empty"><svg fill="none"><use href="#i-music"/></svg><p>Este álbum no tiene pistas.</p></div>`;
  else list.forEach(t => lc.appendChild(trackCard(t)));
  state.tracks = list; state.queue = list.map(t => t.id);
  const playBtn = $('albPlay'); if (playBtn) playBtn.onclick = () => { if (list.length) { state.tracks = list; state.queue = list.map(t => t.id); playTrack(list[0]); } };
  const delBtn = $('albDelete');
  if (mine && delBtn) delBtn.onclick = async () => {
    if (!confirm('¿Borrar el álbum? Las pistas NO se borran, solo se desagrupan.')) return;
    await sb.from('tracks').update({ album_id: null, album_pos: 0 }).eq('album_id', albumId);
    await sb.from('albums').delete().eq('id', albumId);
    toast('Álbum borrado'); openProfile(alb.user_id);
  };
}

/* =======================================================================
   FORO — temas abiertos: texto + archivos (imágenes, audio, vídeo, etc.)
   ======================================================================= */
const FORUM_CATS = [
  { id: 'general', label: 'General' },
  { id: 'beats', label: 'Beats' },
  { id: 'colabs', label: 'Colaboraciones' },
  { id: 'ayuda', label: 'Ayuda' },
  { id: 'feedback', label: 'Feedback' },
  { id: 'offtopic', label: 'Off-topic' },
];
const forumCatLabel = (id) => (FORUM_CATS.find(c => c.id === id) || {}).label || 'General';
const UPVOTE_SVG = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"><polyline points="6 15 12 9 18 15"/></svg>';
let _forumCat = 'all', _forumSort = 'recent', _forumQuery = '';
function forumText(s) { return linkifyMentions(s || '').replace(/\n/g, '<br>'); }
const FORUM_EMOJIS = ['👍', '❤️', '🔥', '😂', '😮', '🙏'];
async function loadForumReactions(threadId, replyIds) {
  const map = {};
  const add = (rows) => (rows || []).forEach(r => { const k = r.target + ':' + r.target_id; (map[k] ||= {}); (map[k][r.emoji] ||= { count: 0, mine: false }); map[k][r.emoji].count++; if (r.user_id === state.user.id) map[k][r.emoji].mine = true; });
  try {
    const { data: tr } = await sb.from('forum_reactions').select('target,target_id,emoji,user_id').eq('target', 'thread').eq('target_id', threadId); add(tr);
    if (replyIds && replyIds.length) { const { data: rr } = await sb.from('forum_reactions').select('target,target_id,emoji,user_id').eq('target', 'reply').in('target_id', replyIds); add(rr); }
  } catch (_) {}
  return map;
}
function reactionBarHTML(target, id, map) {
  const m = (map && map[target + ':' + id]) || {};
  return `<div class="fx-bar" data-fxt="${target}" data-fxid="${esc(id)}">${FORUM_EMOJIS.map(e => { const d = m[e]; const on = d && d.mine; const c = d ? d.count : 0; return `<button class="fx ${on ? 'on' : ''} ${c ? '' : 'fx-empty'}" data-e="${e}">${e}${c ? `<span>${c}</span>` : ''}</button>`; }).join('')}</div>`;
}
function wireReactions(scope) { scope.querySelectorAll('.fx-bar .fx').forEach(b => { b.onclick = () => toggleForumReaction(b); }); }
async function toggleForumReaction(btn) {   // ojo: no llamar toggleReaction — ese nombre lo usa el chat (DM)
  if (btn._busy) return; btn._busy = true;
  const bar = btn.closest('.fx-bar'); const target = bar.dataset.fxt, id = bar.dataset.fxid, emoji = btn.dataset.e;
  const on = btn.classList.contains('on');
  let span = btn.querySelector('span'); const c = span ? (parseInt(span.textContent, 10) || 0) : 0; const nc = on ? c - 1 : c + 1;
  btn.classList.toggle('on', !on);
  if (nc > 0) { if (!span) { span = document.createElement('span'); btn.appendChild(span); } span.textContent = nc; btn.classList.remove('fx-empty'); }
  else { if (span) span.remove(); btn.classList.add('fx-empty'); }
  try {
    if (on) await sb.from('forum_reactions').delete().eq('user_id', state.user.id).eq('target', target).eq('target_id', id).eq('emoji', emoji);
    else await sb.from('forum_reactions').insert({ user_id: state.user.id, target, target_id: id, emoji });
  } catch (_) { btn.classList.toggle('on', on); }
  finally { btn._busy = false; }
}

async function renderForum() {
  setActiveNav('forum');
  const main = $('main'); main.classList.remove('swap'); void main.offsetWidth; main.classList.add('swap');
  main.innerHTML = `
    <div class="main-head"><div><h2>Foro</h2><div class="sub">Habla de lo que quieras con la comunidad</div></div>
      <button class="btn primary" id="newThread"><svg fill="none" stroke="#fff"><use href="#i-plus"/></svg> Nuevo tema</button></div>
    <div class="forum-toolbar">
      <div class="forum-search"><svg fill="none" stroke="currentColor"><use href="#i-search"/></svg><input id="forumSearch" type="text" placeholder="Buscar en el foro…" autocomplete="off" /></div>
      <div class="forum-sort" id="forumSort">
        <button data-s="recent" class="${_forumSort === 'recent' ? 'on' : ''}">Recientes</button>
        <button data-s="top" class="${_forumSort === 'top' ? 'on' : ''}">Populares</button>
        <button data-s="unanswered" class="${_forumSort === 'unanswered' ? 'on' : ''}">Sin responder</button>
      </div>
    </div>
    <div class="forum-cats" id="forumCats">
      <button data-c="all" class="${_forumCat === 'all' ? 'on' : ''}">Todo</button>
      ${FORUM_CATS.map(c => `<button data-c="${c.id}" class="${_forumCat === c.id ? 'on' : ''}">${c.label}</button>`).join('')}
    </div>
    <div id="forumList" class="forum-list"><div class="loading"><div class="spinner"></div></div></div>`;
  $('newThread').onclick = openNewThread;
  const si = $('forumSearch'); si.value = _forumQuery;
  let t; si.oninput = () => { _forumQuery = si.value.trim(); clearTimeout(t); t = setTimeout(loadForumThreads, 250); };
  $('forumSort').querySelectorAll('button').forEach(b => b.onclick = () => { _forumSort = b.dataset.s; $('forumSort').querySelectorAll('button').forEach(x => x.classList.toggle('on', x === b)); loadForumThreads(); });
  $('forumCats').querySelectorAll('button').forEach(b => b.onclick = () => { _forumCat = b.dataset.c; $('forumCats').querySelectorAll('button').forEach(x => x.classList.toggle('on', x === b)); loadForumThreads(); });
  loadForumThreads();
}
async function loadForumThreads() {
  const box = $('forumList'); if (!box) return;
  box.innerHTML = `<div class="loading"><div class="spinner"></div></div>`;
  let q = sb.from('forum_threads').select('*, profiles:user_id(id,username,display_name,avatar_url,theme,verified)');
  if (_forumCat !== 'all') q = q.eq('category', _forumCat);
  if (_forumQuery) { const s = _forumQuery.replace(/[%,]/g, ' '); q = q.or(`title.ilike.%${s}%,body.ilike.%${s}%`); }
  if (_forumSort === 'unanswered') q = q.eq('reply_count', 0).order('created_at', { ascending: false });
  else if (_forumSort === 'top') q = q.order('pinned', { ascending: false }).order('votes', { ascending: false }).order('last_activity_at', { ascending: false });
  else q = q.order('pinned', { ascending: false }).order('last_activity_at', { ascending: false });
  const { data, error } = await q.limit(80);
  if (error) { box.innerHTML = `<div class="empty"><p>No se pudo cargar el foro.</p></div>`; return; }
  if (!data || !data.length) { box.innerHTML = `<div class="empty"><svg fill="none"><use href="#i-comment"/></svg><p>No hay temas aquí todavía.</p></div>`; return; }
  let voted = new Set();
  try { const { data: vs } = await sb.from('forum_votes').select('target_id').eq('user_id', state.user.id).eq('target', 'thread').in('target_id', data.map(t => t.id)); voted = new Set((vs || []).map(v => v.target_id)); } catch (_) {}
  box.innerHTML = '';
  data.forEach(t => box.appendChild(forumThreadRow(t, voted.has(t.id))));
}
function forumThreadRow(t, voted) {
  const p = t.profiles || {};
  const nAtt = Array.isArray(t.attachments) ? t.attachments.length : 0;
  const row = el(`
    <div class="forum-row" data-id="${esc(t.id)}">
      <button class="fvote ${voted ? 'on' : ''}" title="Votar">${UPVOTE_SVG}<b>${t.votes || 0}</b></button>
      <div class="forum-row-main">
        <div class="forum-row-title">${t.pinned ? '<span class="forum-pin"><svg fill="none" stroke="currentColor"><use href="#i-pin"/></svg></span>' : ''}${esc(t.title)}</div>
        <div class="forum-row-meta"><span class="forum-cat">${esc(forumCatLabel(t.category))}</span><span class="frm-dot">·</span><span class="frm-name">${esc(p.display_name || p.username || 'usuario')}</span><span class="frm-dot">·</span><span>${timeAgo(t.last_activity_at)}</span></div>
      </div>
      <div class="forum-row-stats"><span><svg fill="none" stroke="currentColor"><use href="#i-comment"/></svg> ${t.reply_count || 0}</span><span title="Vistas">👁 ${t.views || 0}</span>${nAtt ? `<span><svg fill="none" stroke="currentColor"><use href="#i-paperclip"/></svg> ${nAtt}</span>` : ''}</div>
    </div>`);
  row.onclick = (e) => { if (e.target.closest('.fvote')) return; openThread(t.id); };
  const vb = row.querySelector('.fvote'); vb.onclick = (e) => { e.stopPropagation(); toggleForumVote('thread', t.id, vb); };
  return row;
}
async function toggleForumVote(target, id, btn) {
  if (btn._busy) return; btn._busy = true;
  const voted = btn.classList.contains('on');
  const b = btn.querySelector('b'); const n = parseInt(b.textContent, 10) || 0;
  btn.classList.toggle('on', !voted); b.textContent = voted ? Math.max(0, n - 1) : n + 1;
  try {
    if (voted) await sb.from('forum_votes').delete().eq('user_id', state.user.id).eq('target', target).eq('target_id', id);
    else await sb.from('forum_votes').insert({ user_id: state.user.id, target, target_id: id });
  } catch (_) { btn.classList.toggle('on', voted); b.textContent = n; }
  finally { btn._busy = false; }
}
function editThread(t) {
  const m = openModal(`
    <div class="modal-head"><h3>Editar tema</h3><button class="close">&times;</button></div>
    <div class="modal-body">
      <div class="field"><label>Título</label><input type="text" id="etTitle" maxlength="140" value="${esc(t.title)}" /></div>
      <div class="field"><label>Categoría</label><select id="etCat" class="up-select">${FORUM_CATS.map(c => `<option value="${c.id}" ${t.category === c.id ? 'selected' : ''}>${c.label}</option>`).join('')}</select></div>
      <div class="field"><label>Mensaje</label><textarea id="etBody" maxlength="5000">${esc(t.body || '')}</textarea></div>
      <button class="btn primary" id="etSave">Guardar</button><div class="auth-msg" id="etMsg"></div>
    </div>`);
  attachMentionAutocomplete(m.querySelector('#etBody'));
  m.querySelector('#etSave').onclick = async () => {
    const title = m.querySelector('#etTitle').value.trim(); if (!title) return;
    const { error } = await sb.from('forum_threads').update({ title, category: m.querySelector('#etCat').value, body: m.querySelector('#etBody').value.trim(), edited_at: new Date().toISOString() }).eq('id', t.id);
    if (error) { m.querySelector('#etMsg').className = 'auth-msg error'; m.querySelector('#etMsg').textContent = 'No se pudo guardar.'; return; }
    m.remove(); toast('Tema actualizado'); openThread(t.id);
  };
}
function editReply(r, row) {
  const m = openModal(`
    <div class="modal-head"><h3>Editar respuesta</h3><button class="close">&times;</button></div>
    <div class="modal-body"><div class="field"><textarea id="erBody" maxlength="3000">${esc(r.body || '')}</textarea></div><button class="btn primary" id="erSave">Guardar</button></div>`);
  attachMentionAutocomplete(m.querySelector('#erBody'));
  m.querySelector('#erSave').onclick = async () => {
    const body = m.querySelector('#erBody').value.trim();
    const { error } = await sb.from('forum_replies').update({ body, edited_at: new Date().toISOString() }).eq('id', r.id);
    if (error) { toast('No se pudo guardar'); return; }
    r.body = body; const bodyEl = row.querySelector('.fr-body'); if (bodyEl) bodyEl.innerHTML = forumText(body); else if (body) row.querySelector('.fr-head').insertAdjacentHTML('afterend', `<div class="fr-body">${forumText(body)}</div>`);
    m.remove(); toast('Respuesta actualizada');
  };
}

// sube archivos del foro al bucket público "tracks" (igual que la tienda)
async function uploadForumFiles(files, onProgress) {
  const uid = state.user.id; const out = [];
  for (let i = 0; i < files.length; i++) {
    const f = files[i];
    if (f.size > 50 * 1024 * 1024) { toast(`"${f.name}" supera 50 MB y se omite`); continue; }
    const ext = (f.name.split('.').pop() || 'bin').toLowerCase();
    let furl;
    try { furl = await uploadMedia('tracks', f); } catch (_) { toast('No se pudo subir ' + f.name); continue; }
    out.push({ url: furl, type: f.type || '', name: f.name, size: f.size });
    if (onProgress) onProgress((i + 1) / files.length);
  }
  return out;
}
function attachmentHTML(a) {
  const n = a.name || '';
  if (/^image\//.test(a.type) || /\.(jpe?g|png|gif|webp|avif)$/i.test(n)) return `<a class="att-img" href="${esc(a.url)}" target="_blank" rel="noopener"><img loading="lazy" decoding="async" src="${esc(a.url)}" alt="${esc(n)}"></a>`;
  if (/^audio\//.test(a.type) || /\.(mp3|wav|m4a|aac|flac|ogg|oga|opus)$/i.test(n)) return `<audio class="att-audio" controls preload="none" src="${esc(a.url)}"></audio>`;
  if (/^video\//.test(a.type) || /\.(mp4|webm|mov|m4v)$/i.test(n)) return `<video class="att-video" controls preload="none" src="${esc(a.url)}"></video>`;
  return `<a class="att-file" href="${esc(a.url)}" target="_blank" rel="noopener" download><svg fill="none" stroke="currentColor"><use href="#i-file"/></svg> <span>${esc(n || 'archivo')}</span></a>`;
}
function attachmentsHTML(arr) {
  if (!Array.isArray(arr) || !arr.length) return '';
  return `<div class="att-wrap">${arr.map(attachmentHTML).join('')}</div>`;
}

function openNewThread() {
  if (!requireNotBanned()) return;
  const m = openModal(`
    <div class="modal-head"><h3>Nuevo tema</h3><button class="close">&times;</button></div>
    <div class="modal-body">
      <div class="field"><label>Título</label><input type="text" id="ntTitle" maxlength="140" placeholder="¿De qué quieres hablar?" /></div>
      <div class="field"><label>Categoría</label><select id="ntCat" class="up-select">${FORUM_CATS.map(c => `<option value="${c.id}">${c.label}</option>`).join('')}</select></div>
      <div class="field"><label>Mensaje</label><textarea id="ntBody" maxlength="5000" placeholder="Escribe lo que quieras… (opcional si adjuntas archivos)"></textarea></div>
      <div class="field"><label>Archivos <span style="color:var(--ink-faint);font-weight:400">(imágenes, audio, vídeo, lo que sea)</span></label>
        <div class="dropzone" id="ntDz"><svg fill="none"><use href="#i-paperclip"/></svg><div>Arrastra archivos o haz clic</div></div>
        <input type="file" id="ntFiles" multiple hidden />
        <div id="ntFileList" class="nt-files"></div>
      </div>
      <div class="progress-bar hidden" id="ntBar"><div></div></div>
      <button class="btn primary" id="ntSubmit"><svg stroke="#fff"><use href="#i-send"/></svg> Publicar tema</button>
      <div class="auth-msg" id="ntMsg"></div>
    </div>`);
  let files = [];
  attachMentionAutocomplete(m.querySelector('#ntBody'));
  const dz = m.querySelector('#ntDz'), fi = m.querySelector('#ntFiles'), fl = m.querySelector('#ntFileList');
  const render = () => { fl.innerHTML = files.map((f, i) => `<div class="nt-file"><span>${esc(f.name)}</span><button type="button" data-i="${i}" aria-label="Quitar">&times;</button></div>`).join(''); fl.querySelectorAll('button').forEach(b => b.onclick = () => { files.splice(+b.dataset.i, 1); render(); }); };
  dz.onclick = () => fi.click();
  fi.onchange = () => { files = files.concat(Array.from(fi.files || [])); fi.value = ''; render(); };
  ['dragover', 'dragleave', 'drop'].forEach(ev => dz.addEventListener(ev, (e) => { e.preventDefault(); if (ev === 'dragover') dz.classList.add('drag'); else dz.classList.remove('drag'); if (ev === 'drop' && e.dataTransfer.files.length) { files = files.concat(Array.from(e.dataTransfer.files)); render(); } }));
  m.querySelector('#ntSubmit').onclick = async () => {
    const msg = m.querySelector('#ntMsg'); msg.className = 'auth-msg';
    const title = m.querySelector('#ntTitle').value.trim();
    const body = m.querySelector('#ntBody').value.trim();
    if (!title) { msg.className = 'auth-msg error'; msg.textContent = 'Ponle un título.'; return; }
    if (!body && !files.length) { msg.className = 'auth-msg error'; msg.textContent = 'Escribe algo o adjunta un archivo.'; return; }
    const btn = m.querySelector('#ntSubmit'); btn.disabled = true;
    const bar = m.querySelector('#ntBar'); bar.classList.remove('hidden'); const fill = bar.firstElementChild; fill.style.width = '10%';
    try {
      const attachments = files.length ? await uploadForumFiles(files, p => fill.style.width = (10 + p * 70) + '%') : [];
      fill.style.width = '92%';
      const category = m.querySelector('#ntCat').value || 'general';
      const { data, error } = await sb.from('forum_threads').insert({ user_id: state.user.id, title, body, category, attachments }).select().single();
      if (error) throw error;
      fill.style.width = '100%'; toast('Tema publicado 🎉'); m.remove(); openThread(data.id);
    } catch (err) { console.error(err); msg.className = 'auth-msg error'; msg.textContent = 'Error: ' + (err.message || err); btn.disabled = false; }
  };
}

async function openThread(id) {
  const main = $('main'); main.innerHTML = `<div class="loading"><div class="spinner"></div></div>`;
  sb.rpc('forum_bump_views', { p_id: id }).then(() => {}, () => {});   // .then() es lo que dispara la petición (supabase-js es lazy)
  const { data: t } = await sb.from('forum_threads').select('*, profiles:user_id(id,username,display_name,avatar_url,theme,verified)').eq('id', id).maybeSingle();
  if (!t) { toast('Tema no encontrado'); switchView('forum'); return; }
  const p = t.profiles || {};
  const isAdmin = state.profile.is_admin, mineT = t.user_id === state.user.id, canMod = mineT || isAdmin;
  let votedT = false; try { const { data: v } = await sb.from('forum_votes').select('target_id').eq('user_id', state.user.id).eq('target', 'thread').eq('target_id', id).maybeSingle(); votedT = !!v; } catch (_) {}
  main.innerHTML = `
    <button class="profile-back" id="thBack"><svg fill="none" stroke="currentColor"><use href="#i-chevron-left"/></svg> Foro</button>
    <article class="thread">
      <div class="thread-top">
        <button class="fvote big ${votedT ? 'on' : ''}" id="thVote" title="Votar">${UPVOTE_SVG}<b>${t.votes || 0}</b></button>
        <div class="thread-top-main">
          <div class="thread-cat"><span class="forum-cat">${esc(forumCatLabel(t.category))}</span>${t.solved_reply_id ? '<span class="forum-cat solved">✓ Resuelto</span>' : ''}${t.pinned ? '<span class="forum-cat pin">📌 Fijado</span>' : ''}${t.locked ? '<span class="forum-cat lock">🔒 Cerrado</span>' : ''}</div>
          <h2 class="thread-title">${esc(t.title)}</h2>
          <div class="thread-byline">${avatarHTML(p)}<button class="th-author">${esc(p.display_name || p.username || 'usuario')}${verifiedBadge(p)}</button><span class="frm-dot">·</span><span>${timeAgo(t.created_at)}${t.edited_at ? ' · editado' : ''}</span><span class="frm-dot">·</span><span>👁 ${t.views || 0}</span></div>
        </div>
      </div>
      ${t.body ? `<div class="thread-body">${forumText(t.body)}</div>` : ''}
      ${attachmentsHTML(t.attachments)}
      <div class="thread-fx" id="thFx"></div>
      <div class="thread-tools">
        ${mineT ? `<button class="btn sm" id="thEdit"><svg fill="none" stroke="currentColor"><use href="#i-settings"/></svg> Editar</button>` : ''}
        ${!mineT ? `<button class="btn sm" id="thReport"><svg fill="none" stroke="currentColor"><use href="#i-bell"/></svg> Reportar</button>` : ''}
        ${isAdmin ? `<button class="btn sm" id="thPin">${t.pinned ? 'Desfijar' : '📌 Fijar'}</button><button class="btn sm" id="thLock">${t.locked ? 'Reabrir' : '🔒 Cerrar'}</button>` : ''}
        ${canMod ? `<button class="btn sm" id="thDelete"><svg fill="none" stroke="currentColor"><use href="#i-trash"/></svg> Borrar</button>` : ''}
      </div>
    </article>
    <div class="thread-replies-h" id="repCount"></div>
    <div id="threadReplies" class="forum-replies"><div class="loading"><div class="spinner"></div></div></div>
    ${t.locked ? `<div class="thread-locked">🔒 Tema cerrado a respuestas.</div>` : `
    <form class="forum-reply-form" id="replyForm">
      <div id="rpQuote" class="rp-quote hidden"></div>
      <textarea id="rpBody" maxlength="3000" placeholder="Escribe una respuesta…"></textarea>
      <div class="frf-row">
        <button type="button" class="btn sm" id="rpAttach"><svg fill="none" stroke="currentColor"><use href="#i-paperclip"/></svg> Adjuntar</button>
        <input type="file" id="rpFiles" multiple hidden />
        <span class="frf-names" id="rpNames"></span>
        <button class="btn primary" id="rpSend" type="submit"><svg fill="none" stroke="#fff"><use href="#i-send"/></svg> Responder</button>
      </div>
      <div class="progress-bar hidden" id="rpBar"><div></div></div>
    </form>`}`;
  $('thBack').onclick = () => switchView('forum');
  main.querySelector('.thread-byline .th-author').onclick = () => openProfile(t.user_id);
  $('thVote').onclick = () => toggleForumVote('thread', t.id, $('thVote'));
  if ($('thEdit')) $('thEdit').onclick = () => editThread(t);
  if ($('thReport')) $('thReport').onclick = () => openReportModal('forum', t.id, t.user_id, 'este tema del foro');
  if ($('thPin')) $('thPin').onclick = async () => { await sb.from('forum_threads').update({ pinned: !t.pinned }).eq('id', t.id); openThread(t.id); };
  if ($('thLock')) $('thLock').onclick = async () => { await sb.from('forum_threads').update({ locked: !t.locked }).eq('id', t.id); openThread(t.id); };
  if ($('thDelete')) $('thDelete').onclick = async () => { if (!confirm('¿Borrar este tema y sus respuestas?')) return; const { error } = await sb.from('forum_threads').delete().eq('id', t.id); if (error) { toast('No se pudo borrar'); return; } toast('Tema borrado'); switchView('forum'); };

  // reacciones del tema
  const reMap0 = await loadForumReactions(t.id, []);
  const thFx = $('thFx'); if (thFx) { thFx.innerHTML = reactionBarHTML('thread', t.id, reMap0); wireReactions(thFx); }

  // respuestas
  const box = $('threadReplies');
  const canSolve = mineT || isAdmin;   // quién puede marcar la solución
  let replyTo = null;
  const setReplyTo = (r) => {
    replyTo = r; const q = $('rpQuote'); if (!q) return;
    q.classList.remove('hidden');
    q.innerHTML = `<span>Respondiendo a <b>@${esc(r.profiles?.username || '')}</b></span><button type="button" id="rpQuoteX" aria-label="Quitar">&times;</button>`;
    q.querySelector('#rpQuoteX').onclick = () => { replyTo = null; q.classList.add('hidden'); q.innerHTML = ''; };
    const ta = $('rpBody'); if (ta) { ta.focus(); ta.scrollIntoView({ block: 'center', behavior: 'smooth' }); }
  };

  async function renderReplies() {
    const { data: reps } = await sb.from('forum_replies').select('*, profiles:user_id(id,username,display_name,avatar_url,theme,verified)').eq('thread_id', t.id).order('created_at');
    const list = reps || [];
    const byId = {}; list.forEach(r => byId[r.id] = r);
    let voted = new Set(), reMap = {};
    if (list.length) {
      try { const { data: vs } = await sb.from('forum_votes').select('target_id').eq('user_id', state.user.id).eq('target', 'reply').in('target_id', list.map(r => r.id)); voted = new Set((vs || []).map(v => v.target_id)); } catch (_) {}
      reMap = await loadForumReactions(t.id, list.map(r => r.id));
    }
    // solución primero
    list.sort((a, b) => ((b.id === t.solved_reply_id) - (a.id === t.solved_reply_id)) || (new Date(a.created_at) - new Date(b.created_at)));
    const rc = $('repCount'); if (rc) rc.textContent = list.length ? `${list.length} ${list.length === 1 ? 'respuesta' : 'respuestas'}` : 'Sé el primero en responder';
    box.innerHTML = '';
    if (!list.length) { box.innerHTML = `<div class="empty" style="padding:18px"><p>Sin respuestas aún.</p></div>`; }
    list.forEach(r => box.appendChild(forumReplyRow(r, {
      voted: voted.has(r.id), reMap, parent: r.parent_id ? byId[r.parent_id] : null,
      solvedId: t.solved_reply_id, canSolve, setReplyTo,
      onSolve: async () => {
        const newVal = t.solved_reply_id === r.id ? null : r.id;
        const { error } = await sb.from('forum_threads').update({ solved_reply_id: newVal }).eq('id', t.id);
        if (error) { toast('No se pudo actualizar'); return; }
        t.solved_reply_id = newVal; toast(newVal ? '✓ Marcada como solución' : 'Solución quitada');
        const cat = main.querySelector('.thread-cat'); if (cat) { const ex = cat.querySelector('.solved'); if (newVal && !ex) cat.insertAdjacentHTML('beforeend', '<span class="forum-cat solved">✓ Resuelto</span>'); else if (!newVal && ex) ex.remove(); }
        renderReplies();
      },
    })));
  }
  await renderReplies();

  if (!t.locked) {
    let rfiles = [];
    const fi = $('rpFiles');
    attachMentionAutocomplete($('rpBody'));
    $('rpAttach').onclick = () => fi.click();
    fi.onchange = () => { rfiles = rfiles.concat(Array.from(fi.files || [])); fi.value = ''; $('rpNames').textContent = rfiles.map(f => f.name).join(', '); };
    $('replyForm').addEventListener('submit', async (e) => {
      e.preventDefault();
      if (!requireNotBanned()) return;
      const body = $('rpBody').value.trim();
      if (!body && !rfiles.length) { toast('Escribe algo o adjunta un archivo'); return; }
      const send = $('rpSend'); send.disabled = true;
      const bar = $('rpBar'); bar.classList.remove('hidden'); const fill = bar.firstElementChild; fill.style.width = '12%';
      try {
        const attachments = rfiles.length ? await uploadForumFiles(rfiles, pr => fill.style.width = (12 + pr * 70) + '%') : [];
        const parent_id = replyTo ? replyTo.id : null;
        const { error } = await sb.from('forum_replies').insert({ thread_id: t.id, user_id: state.user.id, body, attachments, parent_id });
        if (error) throw error;
        $('rpBody').value = ''; rfiles = []; $('rpNames').textContent = ''; bar.classList.add('hidden'); fill.style.width = '0%';
        const tgt = (replyTo && replyTo.user_id !== state.user.id) ? replyTo.user_id : (t.user_id !== state.user.id ? t.user_id : null);
        if (tgt) notifySocial('forum_reply', tgt, { thread_id: t.id });
        const q = $('rpQuote'); if (q) { q.classList.add('hidden'); q.innerHTML = ''; } replyTo = null;
        await renderReplies();
      } catch (err) { console.error(err); toast('Error al responder'); }
      finally { send.disabled = false; }
    });
  }
}
function forumReplyRow(r, ctx) {
  ctx = ctx || {};
  const p = r.profiles || {};
  const mine = r.user_id === state.user.id, canMod = mine || state.profile.is_admin;
  const isSolution = ctx.solvedId && ctx.solvedId === r.id;
  const parent = ctx.parent;
  const parentSnip = parent ? (parent.body ? esc(parent.body).slice(0, 90) : '📎 adjunto') : '';
  const row = el(`
    <div class="forum-reply${isSolution ? ' is-solution' : ''}" data-id="${esc(r.id)}">
      ${isSolution ? '<div class="fr-solution">✓ Solución</div>' : ''}
      ${parent ? `<button class="fr-quote" data-pid="${esc(parent.id)}">↳ <b>@${esc(parent.profiles?.username || '')}</b>: ${parentSnip}</button>` : ''}
      <div class="fr-head">${avatarHTML(p)}<button class="th-author">${esc(p.display_name || p.username || 'usuario')}${verifiedBadge(p)}</button><span class="frm-dot">·</span><span>${timeAgo(r.created_at)}${r.edited_at ? ' · editado' : ''}</span></div>
      ${r.body ? `<div class="fr-body">${forumText(r.body)}</div>` : ''}
      ${attachmentsHTML(r.attachments)}
      ${reactionBarHTML('reply', r.id, ctx.reMap)}
      <div class="fr-tools">
        <button class="fvote sm ${ctx.voted ? 'on' : ''}" data-a="vote" title="Votar">${UPVOTE_SVG}<b>${r.votes || 0}</b></button>
        <button class="fr-tool" data-a="reply">Responder</button>
        ${ctx.canSolve ? `<button class="fr-tool ${isSolution ? 'on' : ''}" data-a="solve">${isSolution ? 'Quitar solución' : 'Marcar solución'}</button>` : ''}
        ${mine ? `<button class="fr-tool" data-a="edit">Editar</button>` : ''}
        ${!mine ? `<button class="fr-tool" data-a="report">Reportar</button>` : ''}
        ${canMod ? `<button class="fr-tool" data-a="del">Borrar</button>` : ''}
      </div>
    </div>`);
  row.querySelector('.th-author').onclick = () => openProfile(r.user_id);
  wireReactions(row);
  const pq = row.querySelector('.fr-quote'); if (pq) pq.onclick = () => { const el2 = document.querySelector(`.forum-reply[data-id="${CSS.escape(pq.dataset.pid)}"]`); if (el2) { el2.scrollIntoView({ block: 'center', behavior: 'smooth' }); el2.classList.add('fr-flash'); setTimeout(() => el2.classList.remove('fr-flash'), 1200); } };
  const vb = row.querySelector('[data-a="vote"]'); if (vb) vb.onclick = () => toggleForumVote('reply', r.id, vb);
  const rb = row.querySelector('[data-a="reply"]'); if (rb && ctx.setReplyTo) rb.onclick = () => ctx.setReplyTo(r);
  const sb2 = row.querySelector('[data-a="solve"]'); if (sb2 && ctx.onSolve) sb2.onclick = () => ctx.onSolve();
  const ed = row.querySelector('[data-a="edit"]'); if (ed) ed.onclick = () => editReply(r, row);
  const rep = row.querySelector('[data-a="report"]'); if (rep) rep.onclick = () => openReportModal('forum_reply', r.id, r.user_id, 'esta respuesta del foro');
  const del = row.querySelector('[data-a="del"]'); if (del) del.onclick = async () => { if (!confirm('¿Borrar esta respuesta?')) return; const { error } = await sb.from('forum_replies').delete().eq('id', r.id); if (error) { toast('No se pudo borrar'); return; } row.remove(); };
  return row;
}

function openPhotoUploadModal() {
  if (!requireNotBanned()) return;
  const m = openModal(`
    <div class="modal-head"><h3>Nueva foto</h3><button class="close">&times;</button></div>
    <div class="modal-body">
      <div class="field">
        <label>Foto</label>
        <div class="dropzone" id="dzPhoto">
          <svg fill="none"><use href="#i-image"/></svg>
          <div>Arrastra una imagen aquí o haz clic</div>
          <div class="fname" id="photoName"></div>
        </div>
        <div class="post-photo-prev hidden" id="photoPrev"></div>
        <input type="file" id="fPhoto" accept="image/*" hidden />
      </div>
      <div class="field"><label>Pie de foto (opcional)</label><textarea id="pCaption" maxlength="600" placeholder="Escribe algo sobre tu foto…"></textarea></div>
      <div class="progress-bar hidden" id="ppBar"><div></div></div>
      <button class="btn primary" id="pSubmit"><svg stroke="#fff"><use href="#i-upload"/></svg> Publicar foto</button>
      <div class="auth-msg" id="ppMsg"></div>
    </div>`);

  let photoFile = null;
  const dz = m.querySelector('#dzPhoto'), fP = m.querySelector('#fPhoto'), prev = m.querySelector('#photoPrev');
  const setPhoto = (f) => {
    if (!f || !f.type.startsWith('image')) { toast('Selecciona una imagen'); return; }
    if (f.size > 10 * 1024 * 1024) { toast('La imagen no puede superar los 10 MB'); return; }
    photoFile = f;
    prev.innerHTML = `<img decoding="async" src="${URL.createObjectURL(f)}" alt="" />`;
    prev.classList.remove('hidden');
    m.querySelector('#photoName').textContent = f.name;
  };
  dz.onclick = () => fP.click();
  fP.onchange = () => { if (fP.files[0]) setPhoto(fP.files[0]); };
  ['dragover','dragleave','drop'].forEach(ev => dz.addEventListener(ev, (e) => {
    e.preventDefault();
    if (ev === 'dragover') dz.classList.add('drag'); else dz.classList.remove('drag');
    if (ev === 'drop' && e.dataTransfer.files[0]) setPhoto(e.dataTransfer.files[0]);
  }));

  m.querySelector('#pSubmit').onclick = async () => {
    const caption = m.querySelector('#pCaption').value.trim();
    const msg = m.querySelector('#ppMsg'); msg.className = 'auth-msg';
    if (!photoFile) { msg.className = 'auth-msg error'; msg.textContent = 'Selecciona una imagen.'; return; }
    const btn = m.querySelector('#pSubmit'); btn.disabled = true;
    const bar = m.querySelector('#ppBar'); bar.classList.remove('hidden');
    const fill = bar.firstElementChild; fill.style.width = '20%';
    try {
      const uid = state.user.id;
      const image_url = await uploadMedia('posts', photoFile, (p) => { fill.style.width = (20 + p * 50) + '%'; });
      fill.style.width = '70%';
      const { error } = await sb.from('posts').insert({ user_id: uid, image_url, caption });
      if (error) throw error;
      fill.style.width = '100%';
      toast('¡Foto publicada! 📸');
      m.remove();
      invalidatePosts();
      switchView('posts');
    } catch (err) {
      console.error(err);
      msg.className = 'auth-msg error';
      msg.textContent = 'Error al subir: ' + (err.message || err);
      btn.disabled = false;
    }
  };
}

async function fetchPosts({ userId = null, limit = 50 } = {}) {
  let q = sb.from('posts').select('*, profiles!posts_user_id_fkey(*)');
  if (userId) q = q.eq('user_id', userId);
  q = q.order('created_at', { ascending: false }).limit(limit);
  const { data, error } = await q;
  if (error) throw error;
  return data || [];
}

async function renderPosts() {
  setActiveNav('posts');
  const main = $('main');
  main.classList.remove('swap'); void main.offsetWidth; main.classList.add('swap');
  main.innerHTML = `
    <div class="main-head">
      <div><h2>Fotos</h2><div class="sub">Comparte momentos con la comunidad</div></div>
      <button class="btn primary" id="newPostBtn"><svg stroke="#fff"><use href="#i-camera"/></svg> Nueva foto</button>
    </div>
    <div id="postList" class="post-list"><div class="loading"><div class="spinner"></div></div></div>`;
  $('newPostBtn').onclick = openPhotoUploadModal;

  let posts = [];
  try { posts = await prefetchPosts(); }
  catch (err) { console.error(err); toast('Error al cargar las fotos'); }
  posts = (posts || []).filter(p => !isHidden(p.user_id));

  const list = $('postList'); list.innerHTML = '';
  if (!posts.length) {
    list.innerHTML = `<div class="empty"><svg fill="none"><use href="#i-camera"/></svg><p>Todavía no hay fotos. ¡Pulsa "Nueva foto" y sé el primero!</p></div>`;
    return;
  }
  // qué fotos me gustan (entre las visibles)
  let likedSet = new Set();
  try {
    const ids = posts.map(p => p.id);
    const { data } = await sb.from('post_likes').select('post_id').eq('user_id', state.user.id).in('post_id', ids);
    likedSet = new Set((data || []).map(r => r.post_id));
  } catch {}
  posts.forEach(p => list.appendChild(postCard(p, likedSet.has(p.id))));
}

// caché corta + dedupe para las fotos (permite precargar al deslizar hacia Fotos)
let _postsCache = null, _postsInflight = null;
function prefetchPosts() {
  if (_postsInflight) return _postsInflight;
  if (_postsCache && Date.now() - _postsCache.ts < 10000) return Promise.resolve(_postsCache.posts);
  _postsInflight = fetchPosts().then((p) => { _postsCache = { posts: p || [], ts: Date.now() }; _postsInflight = null; return _postsCache.posts; })
    .catch((e) => { _postsInflight = null; throw e; });
  return _postsInflight;
}
function invalidatePosts() { _postsCache = null; }
function postCard(p, liked) {
  const prof = p.profiles || {};
  const mine = p.user_id === state.user.id;
  const card = el(`
    <div class="track post" data-id="${p.id}">
      <div class="post-head">
        <span class="post-av" data-act="profile">${avatarHTML(prof)}</span>
        <div class="post-who">
          <b data-act="profile">${esc(prof.display_name || prof.username || 'anónimo')}</b>
          <span class="post-time">${timeAgo(p.created_at)}</span>
        </div>
        <div class="post-tools">
          ${mine ? `<button class="post-tool" data-act="edit" title="Editar pie de foto"><svg fill="none" stroke="currentColor"><use href="#i-settings"/></svg></button>` : ''}
          ${!mine ? `<button class="post-tool" data-act="report" title="Reportar publicación"><svg fill="none" stroke="currentColor"><use href="#i-bell"/></svg></button>` : ''}
          ${(mine || state.profile.is_admin) ? `<button class="post-tool danger" data-act="delete" title="Borrar publicación"><svg fill="none" stroke="currentColor"><use href="#i-trash"/></svg></button>` : ''}
        </div>
      </div>
      <div class="post-img"><img src="${esc(p.image_url)}" alt="" loading="lazy" decoding="async" data-act="zoom" /></div>
      ${p.caption ? `<div class="post-caption"><b data-act="profile">@${esc(prof.username || '')}</b> ${linkifyMentions(p.caption)}</div>` : ''}
      <div class="t-foot">
        <span class="time"><svg style="width:12px;height:12px;vertical-align:-2px" fill="currentColor" stroke="none"><use href="#i-heart"/></svg> <span class="likecount">${p.likes_count || 0}</span></span>
        <button class="act like ${liked ? 'on' : ''}" data-act="like"><svg><use href="#i-heart"/></svg><span class="ln">${liked ? 'Te gusta' : 'Me gusta'}</span></button>
        <button class="act" data-act="toggleComments"><svg><use href="#i-comment"/></svg>Comentar</button>
        <button class="act" data-act="share"><svg fill="none" stroke="currentColor"><use href="#i-share"/></svg>Compartir</button>
      </div>
      <div class="comments hidden" data-comments></div>
    </div>`);
  card.addEventListener('click', (e) => handlePostClick(e, p, card));
  attachLongPress(card, () => postMenu(p, card));
  return card;
}

function handlePostClick(e, p, card) {
  const act = e.target.closest('[data-act]')?.dataset.act;
  if (!act) return;
  if (act === 'profile') openProfile(p.user_id);
  else if (act === 'like') togglePostLike(p, card);
  else if (act === 'edit') openEditPost(p, card);
  else if (act === 'delete') deletePost(p, card);
  else if (act === 'report') openReportModal('post', p.id, p.user_id, 'esta publicación');
  else if (act === 'toggleComments') togglePostComments(p, card);
  else if (act === 'share') sharePost(p);
  else if (act === 'zoom') openImageViewer(p.image_url);
}

// Editar el pie de foto de una publicación propia
function openEditPost(p, card) {
  const m = openModal(`
    <div class="modal-head"><h3>Editar publicación</h3><button class="close">&times;</button></div>
    <div class="modal-body">
      <div class="post-photo-prev" style="margin-top:0"><img decoding="async" src="${esc(p.image_url)}" alt="" /></div>
      <div class="field" style="margin-top:12px"><label>Pie de foto</label><textarea id="epCaption" maxlength="600" placeholder="Escribe algo sobre tu foto…">${esc(p.caption || '')}</textarea></div>
      <button class="btn primary" id="epSave">Guardar cambios</button>
      <div class="auth-msg" id="epMsg"></div>
    </div>`);
  setTimeout(() => m.querySelector('#epCaption')?.focus(), 60);
  m.querySelector('#epSave').onclick = async () => {
    const caption = m.querySelector('#epCaption').value.trim();
    const msg = m.querySelector('#epMsg'); msg.className = 'auth-msg';
    const btn = m.querySelector('#epSave'); btn.disabled = true;
    try {
      const { data, error } = await sb.from('posts').update({ caption }).eq('id', p.id).select('*, profiles!posts_user_id_fkey(*)').single();
      if (error) throw error;
      Object.assign(p, data);
      if (card && card.isConnected) {
        const liked = card.querySelector('[data-act="like"]')?.classList.contains('on');
        card.replaceWith(postCard(p, !!liked));
      }
      m.remove();
      toast('Publicación actualizada ✓');
    } catch (err) {
      msg.className = 'auth-msg error';
      msg.textContent = 'Error: ' + (err.message || err);
      btn.disabled = false;
    }
  };
}

async function togglePostLike(p, card) {
  const busy = (togglePostLike._busy ||= new Set());
  if (busy.has(p.id)) return;
  busy.add(p.id);
  const btn = card.querySelector('[data-act="like"]');
  const cntEl = card.querySelector('.likecount');
  const liked = btn ? btn.classList.contains('on') : false;
  const setLn = (txt) => { const ln = btn?.querySelector('.ln'); if (ln) ln.textContent = txt; };
  try {
    if (liked) {
      p.likes_count = Math.max(0, (p.likes_count || 0) - 1);
      btn?.classList.remove('on'); setLn('Me gusta');
      await sb.from('post_likes').delete().eq('post_id', p.id).eq('user_id', state.user.id);
    } else {
      p.likes_count = (p.likes_count || 0) + 1;
      btn?.classList.add('on'); setLn('Te gusta');
      await sb.from('post_likes').insert({ post_id: p.id, user_id: state.user.id });
      notifySocial('post_like', p.user_id);
    }
    if (cntEl) cntEl.textContent = p.likes_count;
  } finally { busy.delete(p.id); }
}

async function deletePost(p, card) {
  if (!confirm('¿Borrar esta publicación? No se puede deshacer.')) return;
  const { error } = await sb.from('posts').delete().eq('id', p.id);
  if (error) { toast('No se pudo borrar'); return; }
  invalidatePosts();
  try { const path = storagePathFromUrl(p.image_url, 'posts'); if (path) await sb.storage.from('posts').remove([path]); } catch {}
  const modal = card.closest('.modal-backdrop');
  card.remove();
  document.querySelector(`.pg-item[data-id="${p.id}"]`)?.remove();
  if (modal) modal.remove();
  toast('Publicación borrada');
}

// Cuadrícula de fotos en el perfil (estilo Instagram)
async function loadProfileEvents(userId, container) {
  container.innerHTML = `<div class="loading" style="padding:24px"><div class="spinner"></div></div>`;
  const [createdRes, savedRes] = await Promise.all([
    sb.from('events').select('*, profiles!events_user_id_fkey(*)').eq('user_id', userId).order('starts_at', { ascending: false }),
    sb.from('event_saves').select('events(*, profiles!events_user_id_fkey(*))').eq('user_id', userId).order('created_at', { ascending: false }),
  ]);
  const created = createdRes.data || [];
  const createdIds = new Set(created.map(e => e.id));
  const saved = (savedRes.data || []).map(r => r.events).filter(e => e && !createdIds.has(e.id));
  if (!created.length && !saved.length) {
    container.innerHTML = `<div class="empty"><svg fill="none"><use href="#i-calendar"/></svg><p>Sin eventos todavía.</p></div>`;
    return;
  }
  container.innerHTML = '';
  if (created.length) {
    container.appendChild(el(`<div class="prof-ev-head">🎤 Organiza</div>`));
    const w = el(`<div class="ev-list"></div>`); created.forEach(ev => w.appendChild(eventCard(ev))); container.appendChild(w);
  }
  if (saved.length) {
    container.appendChild(el(`<div class="prof-ev-head">🎟️ Va a ir</div>`));
    const w = el(`<div class="ev-list"></div>`); saved.forEach(ev => w.appendChild(eventCard(ev))); container.appendChild(w);
  }
}

/* =======================================================================
   TIENDA DEL PERFIL — beats/packs, merch, entradas.
   Cobro DENTRO de UnderBro con Stripe (UnderBro se lleva comisión) o, como
   alternativa, enlace externo del artista; descarga directa si es gratis.
   ======================================================================= */
// Tienda del perfil activada: pestaña "Tienda" en cada perfil (beats/packs/servicios/entradas).
const SHOP_ENABLED = true;
const SHOP_TYPES = {
  beat: { label: 'Beat / Pack', icon: 'i-music' },
  feat: { label: 'Colaboración / FT', icon: 'i-people' },
  service: { label: 'Servicio (mezcla, master…)', icon: 'i-mixer' },
  ticket: { label: 'Entrada / Evento', icon: 'i-calendar' },
  merch: { label: 'Merch', icon: 'i-files' },
  other: { label: 'Otro', icon: 'i-cart' },
};
// Dos secciones mayores: Digital (pago + descarga directa) y Físico (con envío)
const SHOP_KINDS = {
  digital: { label: 'Digital', emoji: '💿', cats: ['beat', 'feat', 'service', 'ticket', 'other'] },
  physical: { label: 'Físico', emoji: '📦', cats: ['merch', 'other'] },
};
function shopKindOf(p) { return p.kind || (p.needs_shipping || p.type === 'merch' ? 'physical' : 'digital'); }
// categorías digitales que se entregan con archivo descargable
const SHOP_DIGITAL_FILE = ['beat', 'feat', 'service', 'other'];
// Columnas seguras de shop_products: NUNCA incluye file_url (el archivo que se
// vende) para que la API pública no lo exponga. La URL solo la dan RPCs seguras
// (shop_owner_file al dueño, shop_free_grab al comprador de un gratis) o el pedido.
const SHOP_PROD_COLS = 'id,user_id,type,title,price,is_free,description,image_url,buy_url,event_date,event_place,sort,created_at,price_cents,currency,pay_inapp,needs_shipping,ship_cents,kind,stock,event_online,event_url,preview_url,has_file';

// ---- Pagos in-app (Stripe Connect) ----
async function payAuthHeaders() {
  try {
    const { data: { session } } = await sb.auth.getSession();
    const tok = session && session.access_token;
    return tok ? { Authorization: 'Bearer ' + tok, 'Content-Type': 'application/json' } : null;
  } catch (_) { return null; }
}
function fmtEur(cents, cur) {
  if (cents == null) return '';
  try { return new Intl.NumberFormat('es-ES', { style: 'currency', currency: (cur || 'eur').toUpperCase() }).format(cents / 100); }
  catch (_) { return (cents / 100).toFixed(2) + ' €'; }
}
// Estado de cobros del vendedor (cacheado por sesión)
let _sellerStatus = null;
async function fetchSellerStatus(force) {
  if (_sellerStatus && !force) return _sellerStatus;
  const h = await payAuthHeaders(); if (!h) return { connected: false, ready: false };
  try {
    const r = await fetch('/api/pay/status', { headers: h });
    _sellerStatus = await r.json();
  } catch (_) { _sellerStatus = { connected: false, ready: false }; }
  return _sellerStatus;
}
async function startSellerConnect(btn) {
  const h = await payAuthHeaders();
  if (!h) { toast('Inicia sesión primero'); return; }
  if (btn) { btn.disabled = true; btn.dataset.t = btn.textContent; btn.textContent = 'Abriendo Stripe…'; }
  try {
    const r = await fetch('/api/pay/connect', { method: 'POST', headers: h });
    const d = await r.json();
    if (d && d.url) { location.href = d.url; return; }
    toast('No se pudo abrir Stripe: ' + (d.error || ''));
  } catch (e) { toast('Error de conexión'); }
  if (btn) { btn.disabled = false; btn.textContent = btn.dataset.t || 'Configurar cobros'; }
}
async function buyInApp(p, btn) {
  if (!state.user) { toast('Inicia sesión para comprar'); return; }
  const h = await payAuthHeaders();
  if (!h) { toast('Inicia sesión para comprar'); return; }
  haptic(12);
  if (btn) { btn.disabled = true; btn.dataset.t = btn.innerHTML; btn.textContent = 'Conectando…'; }
  try {
    const r = await fetch('/api/pay/checkout', { method: 'POST', headers: h, body: JSON.stringify({ product_id: p.id }) });
    const d = await r.json();
    if (d && d.url) { location.href = d.url; return; }
    const map = { seller_not_ready: 'El vendedor aún no tiene los cobros activados.', own_product: 'No puedes comprar tu propio producto.', not_payable: 'Producto no disponible para compra.', sold_out: 'Producto agotado.', physical_disabled: 'Las ventas físicas están desactivadas por ahora.', no_file: 'Este producto aún no tiene el archivo subido. Avisa al vendedor.' };
    toast(map[d.error] || 'No se pudo iniciar el pago.');
  } catch (e) { toast('Error de conexión'); }
  if (btn) { btn.disabled = false; btn.innerHTML = btn.dataset.t || 'Comprar'; }
}
// Descarga de producto GRATIS: deja registro (aparece en "Mis compras" del
// comprador y en la actividad del vendedor) y luego descarga. Si el registro
// falla por lo que sea, se descarga igual — nunca bloquea al usuario.
async function shopFreeDownload(p) {
  haptic(10);
  let url = p.file_url || null;   // el file_url ya no viene en el listado: lo pedimos por RPC seguro
  try {
    if (state.user && p.user_id !== state.user.id) { const { data } = await sb.rpc('shop_free_grab', { p_id: p.id }); url = (data && data[0] && data[0].product_file) || url; }
    else if (state.user) { const { data } = await sb.rpc('shop_owner_file', { p_product: p.id }); url = data || url; }
  } catch (_) {}
  if (!url) { toast('No se pudo obtener el archivo'); return; }
  const a = document.createElement('a'); a.href = czHref(url); a.download = ''; a.target = '_blank'; a.rel = 'noopener'; a.click();
}
// Vuelta desde Stripe (?pay=...)
async function handlePayReturn(pay, sid) {
  if (pay === 'cancel') { toast('Pago cancelado'); return; }
  if (pay === 'connect_done' || pay === 'connect_refresh') {
    _sellerStatus = null;
    const st = await fetchSellerStatus(true);
    toast(st.ready ? '🛍️ ¡Tienda activada!' : 'Alta guardada — Stripe está verificando tus datos');
    return;
  }
  if (pay === 'ok' && sid) { openPurchaseResult(sid); }
}
async function openPurchaseResult(sid) {
  const m = openModal(`<div class="modal-head"><h3>Compra</h3><button class="close">&times;</button></div><div class="modal-body" id="buyRes"><div class="loading" style="padding:24px"><div class="spinner"></div></div></div>`);
  const box = m.querySelector('#buyRes');
  let d = null;
  for (let i = 0; i < 6; i++) { // el webhook puede tardar 1-2s en confirmar
    try { const r = await fetch('/api/pay/order?sid=' + encodeURIComponent(sid)); d = await r.json(); } catch (_) {}
    if (d && d.status === 'paid') break;
    await new Promise(r => setTimeout(r, 1200));
  }
  if (!d || d.status !== 'paid') {
    box.innerHTML = `<div class="empty"><p>Estamos confirmando tu pago. Si ya pagaste, lo recibirás en unos segundos — revisa “Mis compras”.</p></div>`;
    return;
  }
  haptic(20);
  const isTicket = d.type === 'ticket';
  box.innerHTML = `
    <div class="buy-ok">
      <div class="buy-ok-ic">✅</div>
      <h3>¡Pago completado!</h3>
      <p class="buy-ok-sub">${esc(d.title || '')} · ${esc(fmtEur(d.amount_cents, d.currency))}</p>
      ${isTicket ? ticketDeliveryHTML(d) : (d.file_url ? `<a class="btn primary" id="buyDl" href="${esc(czHref(d.file_url))}" target="_blank" rel="noopener"><svg fill="none" stroke="#fff"><use href="#i-download"/></svg> Descargar</a>` : `<p class="buy-ok-sub">El artista te entregará el producto. Te avisaremos por mensaje.</p>`)}
    </div>`;
  if (isTicket && !d.event_online && d.ticket_code) renderQR(box.querySelector('[data-qr]'), d.ticket_code);
}

// HTML de entrega de una entrada (online → enlace · presencial → código + QR)
function ticketDeliveryHTML(d) {
  const when = d.event_date ? `<span class="buy-ticket-meta">${esc(new Date(d.event_date).toLocaleString('es-ES'))}${d.event_place && !d.event_online ? ' · ' + esc(d.event_place) : ''}</span>` : '';
  if (d.event_online) {
    return `<div class="buy-ticket">
      <span class="buy-ticket-l">Entrada · evento online</span>
      ${when}
      ${d.event_url ? `<a class="btn primary" style="margin-top:10px" href="${esc(czHref(d.event_url))}" target="_blank" rel="noopener">💻 Acceder al evento</a>` : '<span class="buy-ticket-hint">El organizador te enviará el acceso.</span>'}
      <span class="buy-ticket-hint">También en “Mis compras”.</span>
    </div>`;
  }
  return `<div class="buy-ticket">
    <span class="buy-ticket-l">Tu entrada</span>
    <div class="ticket-qr" data-qr></div>
    <span class="buy-ticket-code">${esc(d.ticket_code || '')}</span>
    ${when}
    <span class="buy-ticket-hint">Muestra este QR/código en la puerta (un solo uso).</span>
  </div>`;
}

// Cargador perezoso de la librería QR (CDN) + render
let _qrLibP = null;
function loadQRLib() {
  if (window.QRCode && window.QRCode.toDataURL) return Promise.resolve();
  if (_qrLibP) return _qrLibP;
  _qrLibP = new Promise((res, rej) => {
    const s = document.createElement('script');
    s.src = 'https://cdn.jsdelivr.net/npm/qrcode@1.5.4/build/qrcode.min.js';
    s.onload = res; s.onerror = rej;
    document.head.appendChild(s);
  });
  return _qrLibP;
}
async function renderQR(container, text) {
  if (!container || !text) return;
  try {
    await loadQRLib();
    const url = await window.QRCode.toDataURL(text, { width: 180, margin: 1 });
    container.innerHTML = `<img decoding="async" src="${url}" width="180" height="180" alt="QR entrada">`;
  } catch (_) { /* si falla, el código de texto basta */ }
}

async function loadProfileShop(userId, container, isMe) {
  container.innerHTML = `<div class="loading" style="padding:24px"><div class="spinner"></div></div>`;
  let items = [];
  try { const { data } = await sb.from('shop_products').select(SHOP_PROD_COLS).eq('user_id', userId).order('sort', { ascending: true }).order('created_at', { ascending: false }); items = data || []; }
  catch (e) { console.error(e); }
  const render = () => {
    container.innerHTML = '';
    if (isMe) {
      container.appendChild(shopPayBar(userId, () => loadProfileShop(userId, container, isMe)));
      const actions = el(`<div class="shop-actions">
        <button class="btn primary shop-add" id="shopAdd"><svg fill="none" stroke="#fff"><use href="#i-plus"/></svg> Añadir producto</button>
        <button class="btn" id="shopBuys"><svg fill="none" stroke="currentColor"><use href="#i-cart"/></svg> Mis compras</button>
      </div>`);
      actions.querySelector('#shopAdd').onclick = () => openShopEdit(null, userId, () => loadProfileShop(userId, container, isMe));
      actions.querySelector('#shopBuys').onclick = () => openMyPurchases();
      container.appendChild(actions);
    }
    // ventas físicas desactivadas: solo se muestran productos digitales
    const digitalItems = items.filter(p => shopKindOf(p) === 'digital');
    const physicalCount = items.length - digitalItems.length;
    if (!digitalItems.length) {
      container.appendChild(el(`<div class="empty"><svg fill="none"><use href="#i-cart"/></svg><p>${isMe ? 'Tu tienda está vacía. Añade beats, packs, servicios o entradas (productos digitales).' : 'Este artista aún no tiene tienda.'}</p></div>`));
      if (isMe && physicalCount) container.appendChild(el(`<div class="pk-warn" style="margin-top:10px">Tienes ${physicalCount} producto${physicalCount === 1 ? '' : 's'} físico${physicalCount === 1 ? '' : 's'} oculto${physicalCount === 1 ? '' : 's'}: las ventas físicas están desactivadas por ahora.</div>`));
      return;
    }
    const refresh = () => loadProfileShop(userId, container, isMe);
    const grid = el(`<div class="shop-grid"></div>`);
    digitalItems.forEach(p => grid.appendChild(shopProductCard(p, isMe, refresh, soldMap[p.id] || 0)));
    container.appendChild(grid);
    if (isMe && physicalCount) container.appendChild(el(`<div class="pk-warn" style="margin-top:12px">Tienes ${physicalCount} producto${physicalCount === 1 ? '' : 's'} físico${physicalCount === 1 ? '' : 's'} oculto${physicalCount === 1 ? '' : 's'}: las ventas físicas están desactivadas por ahora.</div>`));
  };
  // recuento de ventas por producto (solo para el dueño, para mostrar “N vendidos”)
  let soldMap = {};
  if (isMe) {
    try {
      const { data } = await sb.from('shop_orders').select('product_id').eq('seller_id', userId).eq('status', 'paid');
      (data || []).forEach(o => { if (o.product_id) soldMap[o.product_id] = (soldMap[o.product_id] || 0) + 1; });
    } catch (_) {}
  }
  render();
}

function shopProductCard(p, isMe, refresh, sold) {
  sold = sold || 0;
  const t = SHOP_TYPES[p.type] || SHOP_TYPES.merch;
  const img = p.image_url ? czUrl(p.image_url) : '';
  const soldOut = p.stock != null && p.stock <= 0;
  // digital descargable sin archivo subido: no se puede vender ni entregar
  const missingFile = !p.needs_shipping && p.type === 'beat' && !p.has_file;
  const free = p.is_free && p.has_file && !soldOut;
  const inapp = !p.is_free && p.pay_inapp && p.price_cents >= 50 && !soldOut && !missingFile;
  const cta = p.type === 'ticket' ? 'Conseguir' : 'Comprar';
  const ship = p.needs_shipping && p.ship_cents > 0;
  const priceTxt = p.is_free ? 'Gratis' : (!p.is_free && p.price_cents >= 50 ? fmtEur(p.price_cents, p.currency) : (p.price || ''));
  const stockTag = soldOut ? '<span class="shop-stock out">Agotado</span>'
    : (p.stock != null ? `<span class="shop-stock">Quedan ${p.stock}</span>` : '');
  const card = el(`
    <div class="shop-card${soldOut ? ' is-sold' : ''}">
      <div class="shop-cover" ${img ? `style="background-image:url('${esc(img)}')"` : ''}>${img ? '' : `<svg fill="none" stroke="#fff"><use href="#${t.icon}"/></svg>`}<span class="shop-type">${esc(t.label)}</span>${p.preview_url ? '<span class="shop-prevbadge"><svg fill="none" stroke="currentColor"><use href="#i-play"/></svg>Preview</span>' : ''}${soldOut ? '<span class="shop-soldbadge">AGOTADO</span>' : ''}${isMe ? '<button class="shop-edit" data-act="edit" aria-label="Editar">⋯</button>' : ''}</div>
      <div class="shop-body">
        <div class="shop-title">${esc(p.title || '')}</div>
        ${p.type === 'ticket' && p.event_date ? `<div class="shop-meta">${esc(schedLabel ? schedLabel(p.event_date) : new Date(p.event_date).toLocaleDateString('es-ES'))}${p.event_place ? ' · ' + esc(p.event_place) : ''}</div>` : ''}
        ${p.description ? `<div class="shop-desc">${esc(p.description)}</div>` : ''}
        ${stockTag}${isMe && sold > 0 ? `<span class="shop-sold">${sold} vendido${sold === 1 ? '' : 's'}</span>` : ''}
        ${inapp ? '<div class="shop-secure"><svg fill="none" stroke="currentColor"><use href="#i-lock"/></svg> Pago seguro en UnderBro</div>' : ''}
        <div class="shop-foot">
          <span class="shop-price">${esc(priceTxt)}${ship ? ' <span class="shop-ship">+ envío</span>' : ''}</span>
          ${soldOut ? '<button class="btn sm" disabled>Agotado</button>'
            : (free ? `<button class="btn sm primary" data-act="download"><svg fill="none" stroke="#fff"><use href="#i-download"/></svg> Descargar</button>`
                 : (inapp ? `<button class="btn sm primary" data-act="paybuy">${cta}</button>` : ''))}
        </div>
      </div>
    </div>`);
  card.querySelector('[data-act="paybuy"]')?.addEventListener('click', (e) => { e.stopPropagation(); buyInApp(p, e.currentTarget); });
  card.querySelector('[data-act="download"]')?.addEventListener('click', (e) => { e.stopPropagation(); shopFreeDownload(p); });
  card.querySelector('[data-act="edit"]')?.addEventListener('click', (e) => { e.stopPropagation(); openShopEdit(p, p.user_id, refresh); });
  // tocar la tarjeta abre el detalle del producto (descripción completa + preview)
  card.style.cursor = 'pointer';
  card.addEventListener('click', (e) => { if (e.target.closest('[data-act]')) return; openShopProduct(p, isMe, refresh); });
  return card;
}

// Detalle del producto: portada grande, descripción completa, preview de audio y compra/descarga
function openShopProduct(p, isMe, refresh) {
  const t = SHOP_TYPES[p.type] || SHOP_TYPES.merch;
  const img = p.image_url ? czUrl(p.image_url) : '';
  const soldOut = p.stock != null && p.stock <= 0;
  // digital descargable sin archivo subido: no se puede vender ni entregar
  const missingFile = !p.needs_shipping && p.type === 'beat' && !p.has_file;
  const free = p.is_free && p.has_file && !soldOut;
  const inapp = !p.is_free && p.pay_inapp && p.price_cents >= 50 && !soldOut && !missingFile;
  const priceTxt = p.is_free ? 'Gratis' : (p.price_cents >= 50 ? fmtEur(p.price_cents, p.currency) : (p.price || ''));
  const cta = p.type === 'ticket' ? 'Conseguir' : 'Comprar';
  const m = openModal(`<div class="modal-head"><h3>Producto</h3><button class="close">&times;</button></div>
    <div class="modal-body">
      <div class="shopd-cover" ${img ? `style="background-image:url('${esc(img)}')"` : ''}>${img ? '' : `<svg fill="none" stroke="#fff"><use href="#${t.icon}"/></svg>`}<span class="shop-type">${esc(t.label)}</span>${soldOut ? '<span class="shop-soldbadge">AGOTADO</span>' : ''}${isMe ? '<button class="shop-edit" id="shpEdit" aria-label="Editar">⋯</button>' : ''}</div>
      <div class="shopd-body">
        <div class="shopd-title">${esc(p.title || '')}</div>
        ${p.type === 'ticket' && p.event_date ? `<div class="shop-meta">${esc(new Date(p.event_date).toLocaleString('es-ES', { dateStyle: 'medium', timeStyle: 'short' }))}${p.event_place ? ' · ' + esc(p.event_place) : ''}</div>` : ''}
        ${p.preview_url ? `<div class="shopd-prev"><button class="shopd-play" id="shpPlay" aria-label="Escuchar preview"><svg fill="none" stroke="currentColor"><use href="#i-play"/></svg></button><div class="shopd-prev-m"><b>Escucha un fragmento</b><div class="shopd-bar"><div class="shopd-barfill" id="shpFill"></div></div></div></div><audio id="shpAudio" preload="none" src="${esc(czUrl(p.preview_url))}"></audio>` : ''}
        ${p.description ? `<div class="shopd-desc">${esc(p.description)}</div>` : `<div class="shopd-desc" style="opacity:.6">Sin descripción.</div>`}
        ${p.stock != null && !soldOut ? `<div class="shop-stock">Quedan ${p.stock}</div>` : ''}
        <div class="shopd-foot">
          <span class="shopd-price">${esc(priceTxt)}</span>
          ${soldOut ? '<button class="btn" disabled>Agotado</button>'
            : (missingFile ? '<button class="btn" disabled>No disponible</button>'
              : (free ? `<button class="btn primary" id="shpDl"><svg fill="none" stroke="#fff"><use href="#i-download"/></svg> Descargar</button>`
                 : (inapp ? `<button class="btn primary" id="shpBuy">${cta}</button>` : '')))}
        </div>
        ${missingFile ? '<div class="shop-secure" style="color:#c0533f">Este producto todavía no tiene el archivo subido; el vendedor debe añadirlo antes de venderlo.</div>' : ''}
        ${inapp ? '<div class="shop-secure"><svg fill="none" stroke="currentColor"><use href="#i-lock"/></svg> Pago seguro en UnderBro</div>' : ''}
        ${isMe ? '' : '<button class="mylib-claim" id="shpReport" style="margin-top:10px">Reportar este producto (copyright / estafa)</button>'}
      </div>
    </div>`);
  m.querySelector('#shpReport')?.addEventListener('click', () => openReportModal('product', p.id, p.user_id, '«' + (p.title || 'este producto') + '»'));
  const audio = m.querySelector('#shpAudio');
  if (audio) {
    const btn = m.querySelector('#shpPlay'), fill = m.querySelector('#shpFill'), use = btn.querySelector('use');
    btn.onclick = () => { if (audio.paused) audio.play().catch(() => toast('No se pudo reproducir el preview')); else audio.pause(); };
    audio.onplay = () => use.setAttribute('href', '#i-pause');
    audio.onpause = () => use.setAttribute('href', '#i-play');
    audio.ontimeupdate = () => { if (audio.duration) fill.style.width = (audio.currentTime / audio.duration * 100) + '%'; };
    audio.onended = () => { use.setAttribute('href', '#i-play'); fill.style.width = '0%'; };
  }
  m.querySelector('#shpBuy')?.addEventListener('click', (e) => buyInApp(p, e.currentTarget));
  m.querySelector('#shpDl')?.addEventListener('click', () => shopFreeDownload(p));
  m.querySelector('#shpEdit')?.addEventListener('click', () => { m.remove(); openShopEdit(p, p.user_id, refresh); });
}

// Barra de estado de cobros + ventas para el dueño de la tienda
function shopPayBar(userId, refresh) {
  const bar = el(`<div class="shop-paybar" id="shopPayBar"><div class="spb-line"><span class="spb-ic">💳</span><span class="spb-txt">Comprobando cobros…</span></div></div>`);
  (async () => {
    const st = await fetchSellerStatus(true);
    let sales = null;
    try {
      const { data } = await sb.from('shop_orders').select('amount_cents,ship_cents,status').eq('seller_id', userId).eq('status', 'paid');
      sales = data || [];
    } catch (_) {}
    const net = (sales || []).reduce((s, o) => s + (o.amount_cents || 0) + (o.ship_cents || 0), 0);
    const count = (sales || []).length;
    if (!st.connected) {
      bar.innerHTML = `<div class="spb-line"><span class="spb-ic">🛍️</span><div class="spb-body"><b>Crea tu tienda en UnderBro</b><span>Vende beats, packs, servicios y entradas con cobro seguro y descarga directa.</span></div></div><button class="btn sm primary" id="spbConnect">Crear tienda</button>`;
    } else if (!st.ready) {
      bar.innerHTML = `<div class="spb-line"><span class="spb-ic">⏳</span><div class="spb-body"><b>Verificación en curso</b><span>Stripe está revisando tus datos. Completa el alta si quedó algo pendiente.</span></div></div><button class="btn sm ghost" id="spbConnect">Continuar alta</button>`;
    } else {
      bar.innerHTML = `<div class="spb-line"><span class="spb-ic">👛</span><div class="spb-body"><b>Tienda activa</b><span>${count} venta${count === 1 ? '' : 's'} · ${esc(fmtEur(net, 'eur'))} ingresados</span></div></div><div class="spb-actions"><button class="btn sm primary" id="spbWallet">Monedero</button></div>`;
    }
    bar.querySelector('#spbConnect')?.addEventListener('click', (e) => startSellerConnect(e.currentTarget));
    bar.querySelector('#spbWallet')?.addEventListener('click', () => openWallet(userId));
  })();
  return bar;
}

// Monedero del artista: saldo, ventas y retirar a su banco (panel Stripe)
async function openWallet(userId) {
  const m = openModal(`<div class="modal-head"><h3>👛 Mi monedero</h3><button class="close">&times;</button></div><div class="modal-body" id="walletBody"><div class="loading" style="padding:24px"><div class="spinner"></div></div></div>`);
  const box = m.querySelector('#walletBody');
  const h = await payAuthHeaders();
  let bal = null, sales = [];
  try { if (h) { const r = await fetch('/api/pay/balance', { headers: h }); bal = await r.json(); } } catch (_) {}
  try { const { data } = await sb.from('shop_orders').select('amount_cents,ship_cents,status').eq('seller_id', userId).eq('status', 'paid'); sales = data || []; } catch (_) {}
  let openClaims = 0;
  try { const { count } = await sb.from('shop_claims').select('id', { count: 'exact', head: true }).eq('seller_id', userId).eq('status', 'open'); openClaims = count || 0; } catch (_) {}
  const totalIn = sales.reduce((s, o) => s + (o.amount_cents || 0) + (o.ship_cents || 0), 0);
  const avail = bal && bal.available_cents != null ? bal.available_cents : null;
  const pend = bal && bal.pending_cents != null ? bal.pending_cents : null;
  box.innerHTML = `
    <div class="wallet-bal">
      <div class="wallet-main"><span class="wallet-lbl">Disponible</span><span class="wallet-amt">${avail != null ? esc(fmtEur(avail, 'eur')) : '—'}</span></div>
      <div class="wallet-sub"><span>En camino: <b>${pend != null ? esc(fmtEur(pend, 'eur')) : '—'}</b></span><span>${sales.length} venta${sales.length === 1 ? '' : 's'} · ${esc(fmtEur(totalIn, 'eur'))}</span></div>
    </div>
    <p class="wallet-note">Tus ventas pasan a “Disponible” y Stripe las ingresa en tu cuenta bancaria automáticamente. En el panel de Stripe puedes ver/cambiar tu banco y los pagos.</p>
    <button class="btn primary" id="wSales"><svg fill="none" stroke="#fff"><use href="#i-cart"/></svg> Mis ventas</button>
    <button class="btn" id="wClaims"${openClaims ? ' style="border-color:#e3b7b0;color:#c0533f"' : ''}><svg fill="none" stroke="currentColor"><use href="#i-bell"/></svg> Reclamaciones${openClaims ? ` (${openClaims})` : ''}</button>
    <button class="btn" id="wValidate"><svg fill="none" stroke="currentColor"><use href="#i-calendar"/></svg> Validar entradas</button>
    <button class="btn" id="wBank"><svg fill="none" stroke="currentColor"><use href="#i-download"/></svg> Pagos, banco y retiradas</button>
    <div class="auth-msg" id="wMsg"></div>`;
  m.querySelector('#wSales').onclick = () => { m.remove(); openSellerSales(userId); };
  m.querySelector('#wClaims').onclick = () => { m.remove(); openSellerClaims(userId, false); };
  m.querySelector('#wValidate').onclick = () => { m.remove(); openTicketValidator(); };
  m.querySelector('#wBank').onclick = async (e) => {
    const b = e.currentTarget; b.disabled = true; b.textContent = 'Abriendo Stripe…';
    try {
      const r = await fetch('/api/pay/dashboard', { method: 'POST', headers: h });
      const d = await r.json();
      if (d && d.url) { window.open(d.url, '_blank', 'noopener'); }
      else m.querySelector('#wMsg').textContent = 'No se pudo abrir el panel.';
    } catch (_) { m.querySelector('#wMsg').textContent = 'Error de conexión.'; }
    b.disabled = false; b.innerHTML = '<svg fill="none" stroke="currentColor"><use href="#i-download"/></svg> Pagos, banco y retiradas';
  };
}

// Lista de ventas del artista (con dirección de envío para el merch)
async function openSellerSales(userId) {
  const m = openModal(`<div class="modal-head"><h3>Mis ventas</h3><button class="close">&times;</button></div><div class="modal-body" id="salesBody"><div class="loading" style="padding:24px"><div class="spinner"></div></div></div>`);
  const box = m.querySelector('#salesBody');
  let rows = [];
  try {
    const { data } = await sb.from('shop_orders')
      .select('id,title,type,amount_cents,ship_cents,currency,buyer_id,buyer_email,ship_addr,shipped,paid_at')
      .eq('seller_id', userId).eq('status', 'paid').order('paid_at', { ascending: false }).limit(100);
    rows = data || [];
  } catch (_) {}
  if (!rows.length) { box.innerHTML = `<div class="empty"><svg fill="none"><use href="#i-cart"/></svg><p>Aún no tienes ventas. Cuando alguien compre, aparecerá aquí.</p></div>`; return; }
  const names = await adminNamesByIds(rows.map(r => r.buyer_id));
  box.innerHTML = '';
  rows.forEach(o => {
    const total = (o.amount_cents || 0) + (o.ship_cents || 0);
    const tlabel = (SHOP_TYPES[o.type] || SHOP_TYPES.other).label;
    const who = o.buyer_id ? '@' + (names[o.buyer_id] || '—') : esc(o.buyer_email || '');
    const row = el(`<div class="sale-row">
      <div class="sale-top"><b>${esc(o.title || 'Producto')}</b><span class="sale-amt">${esc(fmtEur(total, o.currency))}</span></div>
      <div class="sale-meta">${esc(tlabel)} · ${o.paid_at ? esc(new Date(o.paid_at).toLocaleDateString('es-ES')) : ''} · <b data-openbuyer style="color:var(--ink);cursor:${o.buyer_id ? 'pointer' : 'default'}">${who}</b></div>
      ${o.buyer_id ? '<button class="btn sm primary" data-msgbuyer style="margin-top:8px"><svg fill="none" stroke="#fff"><use href="#i-send"/></svg> Escribir al comprador</button>' : ''}
      ${o.ship_addr ? `<div class="sale-ship"><svg fill="none" stroke="currentColor"><use href="#i-files"/></svg> Enviar a: ${esc(o.ship_addr)}</div>
        <button class="btn sm ${o.shipped ? '' : 'primary'}" data-ship style="margin-top:8px">${o.shipped ? '✓ Enviado — deshacer' : 'Marcar como enviado'}</button>` : ''}
    </div>`);
    if (o.buyer_id) {
      row.querySelector('[data-openbuyer]').onclick = () => { m.remove(); openProfile(o.buyer_id); };
      row.querySelector('[data-msgbuyer]').onclick = () => { m.remove(); openDM(o.buyer_id, `👋 Hola, sobre tu compra de «${(o.title || 'mi producto').slice(0, 60)}»: `); };
    }
    const sb2 = row.querySelector('[data-ship]');
    if (sb2) sb2.onclick = async () => {
      const nv = !o.shipped;
      sb2.disabled = true;
      const { error } = await sb.rpc('shop_mark_shipped', { o_id: o.id, val: nv });
      sb2.disabled = false;
      if (error) { toast('No se pudo actualizar'); return; }
      o.shipped = nv;
      sb2.className = `btn sm ${nv ? '' : 'primary'}`;
      sb2.textContent = nv ? '✓ Enviado — deshacer' : 'Marcar como enviado';
      toast(nv ? 'Marcado como enviado' : 'Marcado como pendiente');
    };
    box.appendChild(row);
  });
}

// ¿qué tipo de archivo es? (por la extensión de la URL)
function purchaseMediaKind(url) {
  const u = (url || '').toLowerCase().split('?')[0];
  if (/\.(mp3|wav|m4a|aac|ogg|flac|opus)$/.test(u)) return 'audio';
  if (/\.(jpe?g|png|webp|gif|avif|svg)$/.test(u)) return 'image';
  return u ? 'file' : 'none';
}
// Biblioteca de compras: reproduce audio ahí mismo, ve/descarga imágenes,
// entradas con QR. Siempre disponibles (se leen de tus pedidos).
async function openMyPurchases() {
  const m = openModal(`<div class="modal-head"><h3>🛍️ Mis compras</h3><button class="close">&times;</button></div><div class="modal-body" id="buysBody"><div class="loading" style="padding:24px"><div class="spinner"></div></div></div>`);
  const box = m.querySelector('#buysBody');
  let rows = [];
  try {
    const { data } = await sb.from('shop_orders')
      .select('id,title,type,amount_cents,ship_cents,currency,ticket_code,ticket_used,paid_at,file_url,image_url,seller_id,shop_products(image_url,event_date,event_place,event_online,event_url)')
      .eq('buyer_id', state.user.id).eq('status', 'paid').order('paid_at', { ascending: false }).limit(200);
    rows = data || [];
  } catch (_) {}
  if (!rows.length) { box.innerHTML = `<div class="empty"><svg fill="none"><use href="#i-cart"/></svg><p>Aún no has comprado nada. Lo que compres aparecerá aquí siempre, para escucharlo o descargarlo cuando quieras.</p></div>`; return; }
  box.innerHTML = `<div class="mylib-guard"><svg fill="none" stroke="currentColor"><use href="#i-lock"/></svg> Tus compras quedan guardadas aquí <b>para siempre</b>. Descárgalas cuando quieras y, si algo falla, reclama en cada una.</div>`;
  const audios = [];
  rows.forEach(o => {
    const prod = o.shop_products || {};
    // Preferimos la copia guardada en el pedido (siempre disponible aunque borren el producto)
    const fileUrl = o.file_url || prod.file_url || null;
    const imageUrl = o.image_url || prod.image_url || null;
    const total = (o.amount_cents || 0) + (o.ship_cents || 0);
    const free = (o.amount_cents || 0) === 0;
    const st = SHOP_TYPES[o.type] || SHOP_TYPES.other;
    const kind = o.type === 'ticket' ? 'ticket' : purchaseMediaKind(fileUrl);
    const cover = imageUrl
      ? `<img decoding="async" loading="lazy" src="${esc(czUrl(imageUrl))}" alt="">`
      : `<svg fill="none" stroke="currentColor"><use href="#${st.icon}"/></svg>`;
    let ctrl = '';
    if (kind === 'audio') {
      ctrl = `<div class="mylib-player">
        <button class="mylib-play" data-play aria-label="Reproducir"><svg fill="none" stroke="currentColor"><use href="#i-play"/></svg></button>
        <div class="mylib-bar"><div class="mylib-fill" data-fill></div></div>
        <a class="mylib-dl" href="${esc(czHref(fileUrl))}" target="_blank" rel="noopener" title="Descargar"><svg fill="none" stroke="currentColor"><use href="#i-download"/></svg></a>
        <audio preload="none" src="${esc(czUrl(fileUrl))}" data-audio></audio>
      </div>`;
    } else if (kind === 'image') {
      ctrl = `<a class="btn sm primary mylib-btn" href="${esc(czHref(fileUrl))}" target="_blank" rel="noopener"><svg fill="none" stroke="#fff"><use href="#i-image"/></svg> Ver / descargar</a>`;
    } else if (kind === 'ticket') {
      const d = { event_online: prod.event_online, event_url: prod.event_url, event_date: prod.event_date, event_place: prod.event_place, ticket_code: o.ticket_code };
      ctrl = ticketDeliveryHTML(d) + (o.ticket_used ? `<div class="sale-meta" style="margin-top:6px">✓ Entrada ya validada</div>` : '');
    } else if (kind === 'file') {
      ctrl = `<a class="btn sm primary mylib-btn" href="${esc(czHref(fileUrl))}" target="_blank" rel="noopener"><svg fill="none" stroke="#fff"><use href="#i-download"/></svg> Descargar</a>`;
    } else {
      // servicio/encargo (sin archivo): se entrega por chat
      ctrl = `<div class="sale-meta" style="margin-bottom:8px">Servicio bajo pedido: envíale tu material al vendedor por el chat y te devolverá el resultado por ahí.</div>${o.seller_id ? '<button class="btn sm primary mylib-btn" data-contact><svg fill="none" stroke="#fff"><use href="#i-send"/></svg> Escribir al vendedor</button>' : ''}`;
    }
    const row = el(`<div class="mylib-row">
      <div class="mylib-cover">${cover}</div>
      <div class="mylib-body">
        <div class="mylib-top"><b>${esc(o.title || 'Producto')}</b><span class="mylib-amt">${free ? '🎁' : esc(fmtEur(total, o.currency))}</span></div>
        <div class="mylib-meta">${esc(st.label)} · ${o.paid_at ? esc(new Date(o.paid_at).toLocaleDateString('es-ES')) : ''}</div>
        ${ctrl}
        <button class="mylib-claim" data-claim>¿Un problema con esta compra? Reclamar</button>
      </div>
    </div>`);
    box.appendChild(row);
    row.querySelector('[data-claim]').onclick = () => shopOpenClaim(o);
    row.querySelector('[data-contact]') && (row.querySelector('[data-contact]').onclick = () => { m.remove(); openDM(o.seller_id, `📦 Sobre mi compra de «${(o.title || 'tu servicio').slice(0, 60)}». Te paso mi material:`); });
    if (kind === 'ticket' && !prod.event_online && o.ticket_code) renderQR(row.querySelector('[data-qr]'), o.ticket_code);
    if (kind === 'audio') {
      const audio = row.querySelector('[data-audio]'), btn = row.querySelector('[data-play]'), fill = row.querySelector('[data-fill]'), use = btn.querySelector('use');
      audios.push(audio);
      btn.onclick = () => {
        if (audio.paused) { audios.forEach(a => { if (a !== audio) a.pause(); }); audio.play().catch(() => toast('No se pudo reproducir')); }
        else audio.pause();
      };
      audio.onplay = () => use.setAttribute('href', '#i-pause');
      audio.onpause = () => use.setAttribute('href', '#i-play');
      audio.ontimeupdate = () => { if (audio.duration) fill.style.width = (audio.currentTime / audio.duration * 100) + '%'; };
      audio.onended = () => { use.setAttribute('href', '#i-play'); fill.style.width = '0%'; };
    }
  });
  m.querySelector('.close')?.addEventListener('click', () => audios.forEach(a => { try { a.pause(); } catch (_) {} }));
}

// El comprador abre una reclamación de una compra
function shopOpenClaim(order) {
  const m = openModal(`<div class="modal-head"><h3>Reclamar compra</h3><button class="close">&times;</button></div>
    <div class="modal-body">
      <p class="sub" style="margin-top:0">Cuéntanos qué ha pasado con <b>${esc((order.title || 'tu compra').slice(0, 60))}</b>. El vendedor recibirá tu reclamación al instante y el equipo de UnderBro podrá mediar.</p>
      <textarea id="clReason" rows="4" maxlength="1000" placeholder="Ej.: he pagado pero no puedo descargar el archivo · el archivo está corrupto o incompleto · no es lo que se anunciaba…" style="width:100%;box-sizing:border-box;padding:11px 14px;border:1.5px solid var(--line);border-radius:12px;background:var(--panel-2);color:var(--ink);resize:vertical"></textarea>
      <button class="btn primary" id="clSend" style="width:100%;margin-top:10px">Enviar reclamación</button>
      <div class="auth-msg" id="clMsg"></div>
    </div>`);
  m.querySelector('#clSend').onclick = async () => {
    const reason = m.querySelector('#clReason').value.trim();
    const msg = m.querySelector('#clMsg');
    if (reason.length < 3) { msg.className = 'auth-msg error'; msg.textContent = 'Cuéntanos un poco más qué ha pasado.'; return; }
    const btn = m.querySelector('#clSend'); btn.disabled = true; btn.textContent = 'Enviando…';
    const { error } = await sb.rpc('shop_open_claim', { p_order: order.id, p_reason: reason });
    if (error) { btn.disabled = false; btn.textContent = 'Enviar reclamación'; msg.className = 'auth-msg error'; msg.textContent = 'No se pudo enviar. Inténtalo de nuevo.'; return; }
    m.remove(); toast('Reclamación enviada ✓ El vendedor ha sido avisado.');
  };
}
// Reclamaciones recibidas por el vendedor (o todas, si es admin) con opción de marcar resuelta
async function openSellerClaims(userId, asAdmin) {
  const m = openModal(`<div class="modal-head"><h3>⚠️ Reclamaciones</h3><button class="close">&times;</button></div><div class="modal-body" id="claimsBody"><div class="loading" style="padding:24px"><div class="spinner"></div></div></div>`);
  const box = m.querySelector('#claimsBody');
  let rows = [];
  try {
    let q = sb.from('shop_claims').select('id,title,reason,status,created_at,buyer_id,seller_id').order('created_at', { ascending: false }).limit(100);
    if (!asAdmin) q = q.eq('seller_id', userId);
    const { data } = await q; rows = data || [];
  } catch (_) {}
  if (!rows.length) { box.innerHTML = `<div class="empty"><svg fill="none"><use href="#i-bell"/></svg><p>No hay reclamaciones. ¡Todo en orden!</p></div>`; return; }
  const names = await adminNamesByIds(rows.map(r => r.buyer_id));
  box.innerHTML = '';
  rows.forEach(c => {
    const open = c.status === 'open';
    const r = el(`<div class="claim-row ${open ? 'open' : ''}">
      <div class="claim-top"><b>${esc(c.title || 'Producto')}</b><span class="adm-tag ${open ? 'mod' : 'ok'}">${open ? 'Abierta' : 'Resuelta'}</span></div>
      <div class="claim-meta">de @${esc(names[c.buyer_id] || '—')} · ${esc(new Date(c.created_at).toLocaleDateString('es-ES'))}</div>
      <div class="claim-reason">${esc(c.reason || '')}</div>
      ${open ? `<button class="btn sm" data-resolve>Marcar como resuelta</button>` : ''}
    </div>`);
    const rb = r.querySelector('[data-resolve]');
    if (rb) rb.onclick = async () => {
      rb.disabled = true;
      const { error } = await sb.from('shop_claims').update({ status: 'resolved', resolved_at: new Date().toISOString() }).eq('id', c.id);
      if (error) { rb.disabled = false; toast('No se pudo actualizar'); return; }
      toast('Reclamación marcada como resuelta'); m.remove(); openSellerClaims(userId, asAdmin);
    };
    box.appendChild(r);
  });
}

